INSERT INTO book_pages (page_number, section, content, embedding, inserted_at, updated_at) VALUES (7, '2ª PARTE – CIBERNÉTICA APLICADA À ADMINISTRAÇÃO INDUSTRIAL', 'Aristóteles: a dicotomia corpo e alma. Neurofisiologia cibernética. O córtex como braintrust do todo do sistema. Imbricação do modelo neurofisiológico com a organização empresarial. Os críticos do modelo. A falácia do robô. Automatismo e automação. O "Homo faber" como fator de produção. Artesanato e artefato. Uma falácia da informática. A informática como a relação entre a informação, o computador e o sistema. Os usos e abusos dos computadores na administração industrial. O "Projeto Polaris". PERT e computadores. A máquina cibernética.

