INSERT INTO book_pages (page_number, section, content, embedding, inserted_at, updated_at) VALUES (8, 'CAPÍTULO II – Estratégia Anticrise: O Modelo em Ação. — 201', 'Métodos e processos operativos. Disfunções na programação e no controle. Avaliação do potencial produtivo e implantação de um sistema integrado de PCP. Dificuldades a serem afastadas. Coordenação entre as contabilidades gerencial e financeira. Possíveis alternativas de ação. Avaliação das alternativas. Critérios de avaliação. Decisão. Confiabilidade e sinergia. Seleção da melhor alternativa.

## CAPÍTULO II – Estratégia Anticrise: O Modelo em Ação. — 201

