INSERT INTO book_pages (page_number, section, content, embedding, inserted_at, updated_at) VALUES (15, 'Página 15', 'do o comportamento finalista dos seres vivos, interagem e se inter-relacionam sinergicamente face a propósitos teleonômicos comuns, finalidade da organização em termos de realização plena de seu projeto.

O curioso a registrar da obra de Huxley é que, ao escrevê-la, seu intento era de desagravar a Ciência, que pensava estar destruindo os valores humanos e políticos; paradoxalmente, entretanto, colocou no governo do admirável mundo novo um Estado totalitário, organizado sob a égide da Ciência, em que o discernimento e o livre-arbítrio foram completamente erradicados da mente de seus habitantes.

A idéia básica de Huxley — um mundo sistêmico, regido por leis universais que atuam de forma comum nos campos animados e inanimados, uma espécie de mecanismo biológico — teve motivação mais filosófica do que científica. Sua obra dista de 1932, e creio que Viener e Bertalanffy, que trataram da questão sob um enfoque eminentemente científico, sem desprezar, entretanto, o conteúdo filosófico que lhe é inerente, de', '[-0.036546502,-0.0040550646,-0.07579437,-0.07362138,-0.092365064,-0.07914969,-0.008692286,0.09669077,0.025600998,0.10039574,0.03721548,-0.029865239,-0.027270978,0.009114559,-0.035785098,-0.026881676,-0.06860169,-0.022750536,0.026628168,0.10085767,0.101835154,-0.010879274,-0.027639322,0.053506862,-0.05512994,0.012537078,-0.007964958,-0.04027844,-0.0802486,0.00020181295,-0.0195058,0.08650931,0.13253206,-0.04374209,-0.0086036725,0.04597416,0.056236777,-0.063671,-0.04323434,0.021876695,-0.063950785,-0.049403366,-0.065310426,-0.019015836,-0.030695703,-0.038995896,0.02627652,-0.00015448492,-0.048853263,-0.096330345,-0.11898447,-0.024710108,-0.06981407,0.022384556,-0.05409075,-0.009115381,-0.041680805,0.042506892,-0.00830039,-0.023803066,0.0035321226,0.019746415,-0.031647723,0.05325931,0.032770555,0.04076995,0.011214835,0.005218012,0.008581843,-0.028827732,0.06708175,-0.05432762,0.07772217,-0.024474138,0.03358773,0.025695546,-0.04644053,0.029319623,0.05487434,-0.06136038,0.05750726,0.006206092,-0.046804845,-0.05066013,0.009755903,0.054266434,-0.057776555,0.077947795,-0.027424188,-0.0259612,-0.05121796,0.0019196237,-0.04621294,-0.023102902,0.013973758,-0.0053908215,0.0010019069,-0.046820387,0.09647675,-0.06034241,-0.006733201,0.00053200696,-0.018890075,0.034732077,0.0030851285,-0.043648455,-0.025792098,-0.07739604,0.06126901,0.08027828,-0.097593896,-0.032534648,-0.08780318,0.034518648,0.02062355,-0.002890486,0.015604723,-0.060425084,0.072581835,-0.042115215,-0.0065314705,-0.10419093,0.030343663,-0.112036765,0.06995111,-0.018894756,0.0053952727,6.394967e-33,-0.0531