INSERT INTO book_pages (page_number, section, content, embedding, inserted_at, updated_at) VALUES (16, 'Página 16', 'vem a Huxley a primazia da incursão nos futuros domínios da cibernética e dos sistemas.

Cibernética e Sociedade — o uso humano dos seres humanos, e Teoria Geral dos Sistemas (ver bibliografia), confirmaram a intuição nascida com a leitura do Admirável Mundo Novo e constituíram minha iniciação na cibernética. A partir daí, a idéia de escrever este livro foi tomando força à medida que chegavam ao Brasil os novos progressos da cibernética, através de autores estrangeiros traduzidos para o vernáculo. Duas particularidades reforçavam, também, dia a dia, a idéia, em fase de maturação. A primeira delas, o fato de se tratar de uma Ciência que dispensa, tanto em seu aspecto puro quanto no aplicado, o uso de materiais e equipamentos especificamente destinados à realização de experimentos e de aplicações práticas. O laboratório do ciberneta poderá ser, sem maiores restrições, seu próprio pensamento, sua imaginação criadora, alimentada, muitas vezes, pela intuição, enquanto que o campo de provas de suas inferências poderá ser desde seu ambiente de trabalho ou seu domicílio até o caminho percorrido', '[0.03057322,-0.023881126,-0.06435141,-0.05529246,-0.04496297,0.010113403,0.018757034,0.08187381,0.041517705,0.12991266,0.02522182,-0.01593971,-0.005512205,-0.028157488,-0.035627354,-0.029223733,0.0037781226,0.032912496,-0.012903589,0.045530822,0.13531101,-0.031381197,-0.040081058,0.041425988,-0.094970755,0.052305683,-0.031163478,-0.030967828,-0.076130554,-0.043449413,-0.015272225,0.055306196,0.13197409,-0.05563778,-0.016413523,-0.004644279,0.028430248,-0.062196508,-0.033275373,0.06103961,-0.0234777,-0.038439598,-0.053111266,0.00948468,-0.0063263034,0.010976168,0.042264406,0.028774068,-0.033108223,-0.029231546,-0.0623972,-0.0022129286,-0.10633575,0.02738197,-0.027544348,-0.054552674,-0.014592798,-0.036797877,-0.030049913,-0.017923128,-0.013516319,0.032692764,0.019317452,0.04259237,0.06690565,0.03305482,0.0141993705,0.027326278,0.021056432,-0.026120184,0.05353657,-0.030564526,0.0809641,0.03791662,-0.0053775227,0.08744082,0.03437226,0.037524097,0.001727537,-0.078532025,0