INSERT INTO book_pages (page_number, section, content, embedding, inserted_at, updated_at) VALUES (21, 'Página 21', 'presarial de forma a impelir a curva das possibilidades de produção para as proximidades do ponto de locação das satisfações humanas, única resposta cabal ao grave desafio do presente.

Dentro dessa ordem de idéias — formulação de estratégias de ação apriorístico — desenvolveu-se, neste trabalho, a metodologia a que se deu, talvez presunçosamente, o título de "SISTEMA" INTEGRADO DE PROGRAMAÇÃO E CONTROLE DE PRODUÇÃO — Um modelo cibernético de administração industrial, que visa a instituir, no organismo empresarial, um sistema físico de produção, ciberneticamente operado por um sistema de gestão administrativo de concebido.

A obra desenvolve-se em duas partes. Na primeira — ELEMENTOS DE CIBERNÉTICA — são feitas rápidas incursões nos domínios puros desta jovem ciência, visando a familiarizar o leitor com os termos e conceitos que lhe darão acesso ao novo instrumental de otimização da performance empresarial. Na segunda parte — CIBERNÉTICA APLICADA À ADMINISTRAÇÃO INDUSTRIAL — a ciência pura, teórica, terá aplicação prática na solução', '[-0.008337548,0.0012984931,-0.07632126,-0.03002765,-0.030506356,0.019256767,-0.036449544,0.0873507,0.0001197483,0.10712071,0.07360773,-0.05600381,0.022083698,-0.0114274435,0.013494285,-0.060760092,0.03872374,-0.005795729,-0.04766891,0.039250206,0.15128855,-0.073316626,-0.088364616,0.02356113,-0.069073744,0.013385455,-0.043082602,-0.0074511874,-0.02661412,-0.03751698,0.00027014938,0.04051767,0.16408992,0.004286704,-0.0016579516,0.0452925,0.025709677,-0.040423095,0.011177068,0.05334737,-0.090533726,-0.03290639,-0.10131684,-0.09861417,0.005075705,0.01645148,0.04524203,0.012298751,-0.08277831,-0.06604744,-0.06735684,0.029095232,-0.04128211,0.01633586,0.03791122,-0.069092065,0.024878092,-0.048211098,-0.048125844,-0.040257778,-0.05200205,-0.005406827,-0.023471883,-0.013934179,0.04521233,0.020466428,-0.04385827,-0.00011489561,-0.0146974055,-0.018062992,0.038710125,-0.024336232,-0.019393861,0.014350119,-0.0035234045,0.006900662,0.041443016,0.029814107,-0.0188134,-0.12204352,0.04728539,0.089754306,-0.04487705,-0.012500197,-0.015153252,0.017660093,-0.015913432,0.033043317,0.03736053,0.001944361,-0.022342693,0.036103714,-0.05924218,-0.04604705,0.038911335,0.029321715,-0.005673368,-0.02104862,0.060955312,-0.048672155,0.056139976,-0.0042066923,-0.009284603,-0.038544916,-0.050640058,-0.02115369,-0.019795619,-0.018780932,0.047765434,0.10631887,-0.08556918,-0.062541984,-0.14469472,-0.04630346,-0.054900035,-0.036174793,-0.006783028,-0.050352313,0.05061271,-0.028122434,0.060864795,-0.052607358,0.07736358,-0.048994705,0.058113415,0.005274204,0.020668123,6.079811e-33,-0.095