INSERT INTO book_pages (page_number, section, content, embedding, inserted_at, updated_at) VALUES (32, 'Página 32', 'O exemplo histórico, que, apesar de narrado em estilo burlesco, guarda absoluta fidelidade com os reais acontecimentos, oferece uma visão clara da sintomatologia da síndrome antiprogresso: uma tendência ao isolamento dos campos do saber em compartimentos estanques, sem intercomunicação. O por quê dessa atitude mental de isolamento dos campos do saber — etiologia da síndrome — iremos encontrar nos domínios da Filosofia.

Há dois conceitos básicos para o perfeito entendimento da Filosofia de Platão: o conceito de "universal" e o conceito de "particular". Toda idéia encerra um conteúdo do universal, comum às coisas de uma maneira geral, que deve ser tomado como ponto focal na análise do processo de formação do conhecimento. Assim, o gênero, um particular, prescinde da espécie, um universal, para sua completa caracterização. Não se atinge a essência das coisas sem se passar pelo conhecimento das substâncias de que são formadas. Ao exprimir, como fruto da universalidade de seu pensamento, a idéia das coisas, impregnadas do sentido da tota', '[-0.006862134,0.034694456,-0.075209826,-0.018997818,-0.06816118,0.014414668,0.015701154,0.07133642,-0.06381743,0.04484861,0.07693678,-0.024779351,-0.069657415,0.027673304,-0.013552498,-0.018792704,0.009971658,0.05583748,-0.011625734,0.07642837,0.09314062,-0.031733166,0.0057931044,0.025471315,-0.16536559,0.058778547,-0.014535214,-0.035948347,-0.029664205,-0.02822536,-0.0349066,0.0478158,0.14480194,-0.030861216,0.010491373,-0.008933653,-0.022509102,-0.046510037,-0.03578935,0.017050559,-0.07684684,-0.00164071,-0.021832058,0.00858595,-0.00058770354,-0.08149,0.0034529257,0.07065919,-0.0031001978,-0.0020308816,-0.04551171,-0.022665296,-0.047305893,0.022887064,0.004742785,-0.026036482,0.02427583,-0.029231355,-0.042357013,0.060222223,-0.044643287,0.018147122,-0.011157748,0.03592268,0.030110225,0.037662134,-0.025303476,-0.043250777,0.013041609,0.029072048,0.04031815,-0.09892979,-0.010177076,0.07110993,-0.0142326215,0.087915555,-0.05289301,0.06869034,-0.059268504,-0.0741714,0.004984083,0.0453355,0.012019707,-0.04809605,0.09786871,0.024463402,-0.02996173,0.051049978,-0.017039284,0.026468378,-0.034193218,0.00927527,-0.07404481,-0.08625328,0.08124606,-0.0018074422,-0.0066328547,-0.049886618,0.051280003,-0.06294087,0.06482386,-0.07769667,0.016162902,0.036357444,-0.006346874,-0.00311345,0.012216078,-0.09363995,-0.013462738,0.026766066,-0.086534895,-0.019019406,-0.