INSERT INTO book_pages (page_number, section, content, embedding, inserted_at, updated_at) VALUES (61, 'Página 61', 'Com auxílio do praxeograma operatório da figura 4 acompanhemos o comportamento global do sistema, a partir do momento em que Pesquisa detectou a perturbação.

<u>Seta nº 1</u> — indica a atuação de Pesquisa sobre Produção, reduzindo-lhe o ritmo operatório a fim de evitar que, face à retração do mercado, o lote econômico ultrapasse seu nível em Estoque;

<u>Seta nº 2</u> — indica a atuação de Pesquisa sobre o mercado, no sentido de auscultar as causas de rejeição do item crítico (ou melhor, tornado crítico);

<u>Seta nº 3</u> — indica que Pesquisa recebe do mercado as informações requeridas e, após processá-las, transmite, para Produção, um novo "design" do item crítico e, para Vendas, sugestões sobre "marketing", uma vez que a política de vendas da empresa, não apenas as características do item crítico, foram pontos fracos explorados pelo concorrente;

---

(Continuação da pág. anterior) *de limiar entre o "a priori" e o "a posteriori". Mais adiante ver-se-á que o mecanismo de auto-regulação opera em tempo real.*', '[-0.02637985,0.087298274,-0.074921235,-0.027751964,0.032090124,-0.0068084206,0.028659001,0.06897109,0.037796725,0.07130838,0.008465001,-0.027844075,0.053741824,-0.07558289,-0.030122932,0.013449755,0.07726194,0.035127416,-0.060605466,0.021065483,0.17886826,-0.04434973,-0.021974823,0.04828038,-0.078670435,0.03473024,-0.014180859,0.09302779,0.0040508364,-0.073107205,-0.012455464,0.05044292,0.095124274,-0.023972176,0.007486853,0.023432694,0.010406287,-0.05234476,-0.073440045,0.044272035,-0.05747437,0.03070349,-0.06322229,-0.03965661,0.013385508,0.0015633076,0.08368976,-0.021587206,-0.029823393,-0.020491986,-0.053980928,0.004966175,-0.021715505,-0.12093317,-0.011207682,0.0024899943,0.023354674,-0.014772246,0.03903812,-0.035698615,-0.010961614,-0.014076619,-0.04273729,0.04073717,0.059811484,-0.004162809,-0.038570315,0.013153158,-0.042885404,-0.0019446389,0.021549005,-0.04939591,0.09030712,0.035025466,0.01727671,0.031741273,0.060582466,-0.041347105,-0.026191434,-0.13211386,0.018637259,-0.004703462,-0.020246854,-0.09472497,0.028275643,0.007936155,0.004774227,0.016912196,0.08800203,0.025774943,0.008726658,-0.011996651,-0.08408657,0.00061158405,0.010069727,0.047179293,-0.02686491,-0.022606712,0.0644358,0.0049224054,0.061773453,0.016803661,0.04919539,-0.038319875,-0.035518724,-0.03369865,-0.041397966,-0.014448201,0.05800408,0.07030745,-0.07857932,-0.028911285,-0.052863356,-0.078301325,-0.010865806,-0.059723586,-0.028011981,-0.038117368,-0.06551309,-0.028477972,0.06370137,-0.07566131,0.0148060685,-0.019155536,0.0525123,-0.018895498,0.043342408,1.14639896e-32,-0.05126897,-0.084359325,-0.04295323,-0.033253737,-0.002102096,0.0010475583,-0.035633698,-0.0013816565,0.05479643,0.032006364,-0.030252784,0.07891824,-0.06266092,0.110827565,0.09188029,0.0088668335,0.10166148,-0.025047446,0.01176963,-0.05912775,-0.05996942,-0.04304