INSERT INTO book_pages (page_number, section, content, embedding, inserted_at, updated_at) VALUES (29, 'Página 29', 'beram que lhes faltava auto-sustentação, detiveram o crescimento de suas empresas, como medida profilática; aqueles que não tiveram esse descortino, entraram, logo em seguida, em crise, a que muitos, mesmo sem que conscientemente atentassem para as causas do fenômeno, definiram com exatidão: "crise de crescimento..."

O que ocorreu com a Metodologia do Controle repetiu-se, de maneira semelhante, em outros campos do conhecimento humano, parecendo configurar-se a ação patológica de uma espécie de "Síndrome Antiprogresso", a desafiar a inteligência e a perspicácia dos cientistas e de todos os homens de saber. Um dos efeitos dessa síndrome, no campo da administração, foi o advento da burocracia como um fim em si mesmo, e a sua valorização, além da medida, na horizontalização da metodologia do controle. Não sendo capaz de inovar, o Burocrata-Administrador, categoria de executivos emergentes em ocasiões de crise, passou a vestir velhas e já obsoletas rotinas com roupas novas e vistosas, destituídas, entretanto, da eficácia que se esperava delas.', '[0.025263706,0.04885951,-0.080955066,-0.024853524,0.008424039,0.058495503,0.057665635,0.116882816,-0.037431076,0.048543025,0.05831665,-0.04328731,0.013812416,0.013511093,-0.04124494,-0.021987302,-0.009835646,0.04076896,0.04341091,0.056083195,0.105792455,-0.04408217,-0.009816136,0.07712598,-0.14596568,0.074641034,-0.039426565,-0.01932707,-0.061368283,0.01674736,0.019774012,0.030733634,0.15595728,-0.007403546,0.011749362,0.010984788,0.043591734,-0.044600826,-0.00027898815,0.09074089,-0.08394975,0.0012240037,-0.10395562,-0.057204876,0.013430356,-0.06560006,0.0564335,0.10077115,-0.035489466,-0.034270152,-0.03174087,-0.02757575,-0.053958807,0.012084088,-0.024031544,-0.04231303,0.0329141,-0.014621217,0.012373805,0.030629966,-0.053809006,0.022173489,0.03128147,0.037004184,0.023107914,0.0017963194,-0.02324595,-0.008448252,0.019761052,0.06266443,0.044060394,-0.10788624,-0.015200951,0.047733717,0.0008259511,0.06873739,-0.084509745,0.029484447,0.014877941,-0.11777999,0.028257366,0.03146272,0.061691105,-0.031146923,0.06644756,0.020813977,-0.01082454,0.018202709,0.06768413,0.0052707456,-0.016181063,0.056690544,-0.071901634,-0.07732437,-0.0032509142,-0.02344455,-0.024308467,-0.039188243,0.029791374,-0.03472239,0.013104073,-0.012487702,0.041763496,0.034536