INSERT INTO book_pages (page_number, section, content, embedding, inserted_at, updated_at) VALUES (31, 'Página 31', 'Ação: nossos personagens, embora desprovidos dos mais elementares recursos ópticos, teimam em perscrutar o firmamento, com autêntico interesse científico, na ânsia de formular leis físicas coerentes com a realidade objetiva, intuída por suas mentes guiadas pela chama divina do saber.

Além dos bastidores, absorvidos por suas tarefas artesanais, os primeiros oculistas da história, para os quais o Céu nada mais representa que a simples abóbada onde de brilham o sol e as estrelas, e rugem trovões, imprimem, maquinalmente, o polimento em suas lentes, seguramente desinteressados pelo destino das galáxias...

Muitos e muitos atos se passaram no teatro da vida antes que se apercebessem, os personagens em cena, da existência, além dos bastidores, dos artistas que faltavam para completar o elenco da grande peça da natureza. Ao se conhecerem, certamente, por mera obra do acaso, sentiram-se ligados por interesses comuns, e, juntos, construíram a rudimentar luneta que revolucionou "ubi et orbi".', '[-0.00528311,-0.0106225675,0.015937049,-0.037754755,-0.06101823,0.011239999,0.036945067,0.08382428,0.046250895,0.03225443,0.07106577,-0.107157156,0.011382353,-0.009628609,-0.034672484,-0.023349965,-0.00059809856,0.053195015,0.015670558,0.14303868,0.13314675,-0.049225472,-0.11681998,0.09643961,-0.10837431,0.075088255,0.036334388,-0.039574888,-0.071861744,-0.047485467,-0.03415091,0.0065195323,0.08168613,-0.020651326,-0.033672422,0.009341459,0.0389882,-0.045543432,-0.023910927,0.09888748,-0.043082107,0.0039929375,-0.07328454,-0.025473783,0.018291354,-0.09235775,0.039531782,0.01812379,0.011487613,-0.022173585,-0.1191321,0.020540033,-0.110874034,0.02317438,0.009275519,-0.019803183,-0.049591124,-0.08647385,0.043152288,-0.060119834,0.0033537238,0.024647119,0.046718765,0.07875761,0.029278804,0.02267051,-0.002294974,0.010177778,-0.033030562,0.058876216,0.0286707,-0.04138654,-0.016384864,0.021325063,-0.074441426,0.115827516,-0.0017512256,-0.035597008,-0.006312383,-0.09851117,-0.011514346,-0.022432685,-0.01562788,-0.055483267,0.06000087,0.052361507,0.03955271,-0.0050305817,-0.027115023,-0.047477406,-0.016034821,0.009672283,-0.11973633,-0.029401332,0.06159904,0.008661176,0.0100666275,-0.08343214,0.0796426,-0.02179846,0.021854322,0.053638477,0.058168884,-0.004653281,-0.050439153,0.031348113,-0.017934626,-0.05943184,0.009726301,0.106825046,-0.06564249,-0.045028012,-0.09650683,-0.0055473945,-0.014494759,0.004329434,-0.031717844,-0.07364527,-0.0013169151,-0.0014792524,-0.0011672475,-0.07005724,0.08272196,-0.0179477,0.0392328,0.0048370697,0.055648156,1.4902103e-32,-0.044395387,-0.076572366,-0.012936