INSERT INTO book_pages (page_number, section, content, embedding, inserted_at, updated_at) VALUES (78, 'Página 78', 'A variedade de um sistema — esta expressão tem grande significado para a cibernética — é função do número de transições que o mesmo efetua para cada transformação, e sua medida dá a quantidade de informação (energia ou negentropia) necessária para a operação do sistema.

O conhecimento da variedade de um sistema, obviamente, constitui um dado de grande importância. Primeiramente, para quantificar a energia necessária à sua operação; em segundo lugar, para decidir, entre dois ou mais sistemas, qual o mais econômico para a consecução de um dado propósito. Há muitas outras razões, cuja enumeração deixamos por conta da curiosidade e da perspicácia do leitor.

A Teoria da Informação desenvolveu um modelo matemático para a determinação da variedade. O modelo presume que o sistema seja operado com o máximo rendimento, isto é, que as transições se façam dentro de uma lógica capaz de remover a incerteza (o mesmo que aumentar a entropia) com o mínimo consu', '[0.02722659,0.005611014,-0.096483044,-0.044078577,-0.06262854,0.0012635505,-0.03376487,0.0790716,0.039222244,0.07112582,0.06066447,-0.03362338,-0.00797088,0.025703572,0.037277453,-0.02073441,0.05789439,0.05815751,-0.057967152,0.052340057,0.17978217,-0.061424617,-0.07269951,0.00994421,-0.07696612,0.03812364,-0.0049731047,-0.028867554,-0.029350858,-0.0664874,-0.031138893,0.08409922,0.08859732,0.0028510618,-0.018544197,-0.01745562,0.038625717,-0.029510913,-0.0013104074,0.075533845,-0.05855614,-0.0034727617,-0.049633343,-0.07403596,0.04054804,0.0022323392,0.027295832,0.035500385,-0.026230587,-0.057803534,-0.071895316,-0.01966067,-0.06808571,0.035832874,-0.019439919,-0.08013501,-0.0036353797,-0.042531867,0.00087266014,0.002615926,-0.03157503,0.045999918,0.011211655,0.005709601,0.019523486,-0.0032920605,-0.05508654,-0.0010272273,-0.04691185,-0.0032801009,0.026716495,-0.046570294,0.01506247,0.029838074,-0.028932674,0.033624563,0.034942664,0.003056098,-0.022497637,-0.11335667,0.018733727,0.049635056,-0.05057202,-0.025165146,0.009619635,-0.005387167,-0.03410393,0.016165612,0.04376647,0.024707785,0.008329241,0.033746958,-0.03876601,-0.07871942,0.06861003,0.0030023917,-0.014309761,-0.054564346,0.0845918,-0.0747478,0.054710574,0.010183141,0.062717594,-0.043487113,-0.021197686,-0.030607097,-0.029634604,-0.0006984095,0.046577133,0.1327594,-0.11191813,-0.019333951,-0.13302903,-0.066369005,-0.021087855,-0.08259963,0.018933596,-0.0431402,-0.004897568,-0.016974596,0.033696562,-0.08254002,0.038922496,-0.015442209,0.057673257,0.0041592848,-0.006223294,8.268897e-33,-0.08199327,-0.03407279,-0.026962923,0.047385927,0.00067002705,0.071587384,-0.011239154,-0.0061730347,0.050827738,0.05281743,-0.1