INSERT INTO book_pages (page_number, section, content, embedding, inserted_at, updated_at) VALUES (55, 'Página 55', 'renemente. Já os propósitos atuais variam com as necessidades imediatas de cada sistema e se traduzem em metas e objetivos cuja conquista e preservação, no tempo e no espaço, irá depender da dinâmica própria do sistema considerado. Interessante exemplo de tais propósitos oferece-nos a Ciência Política, no que concerne aos Objetivos Nacionais, atuais (ONA) e permanentes (ONP).

As nações, como sistemas políticos, têm, como ONP: Integridade Territorial, Integração Nacional, Progresso, Paz Social e Soberania. Já os ONA poderão, ou não, ser: combate à inflação, desenvolvimento do setor terciário da economia, contenção (ou estímulo) da natalidade etc.

O propósito permanente — sobrevivência a longo prazo, se possível perenemente — encontra respaldo, como acabamos de ver, na capacidade que o sistema precisa ter de evoluir no contexto da espécie, evolução que afeta, positivamente, as metas e objetivos atuais do sistema. Tal a razão pela qual se traçarmos a imagem cartesiana da vida de um sistema detectaremos uma tendência, acentua', '[-0.0066317893,0.015601098,-0.046544924,0.007957162,-0.014193405,0.011429218,-0.014803281,0.07121889,-0.0139071215,0.10330461,0.07075578,-0.015321073,-0.031511586,-0.00034778644,0.011098976,-0.004701854,0.009739082,0.008985823,-0.03719939,0.08156326,0.108320564,-0.09994598,-0.0722514,0.07438973,-0.029656537,0.011786742,-0.015761396,0.018593168,-0.030749328,-0.006847282,-0.018985434,0.08127951,0.045220483,-0.04080021,0.050603136,0.04692666,0.048117988,-0.014582683,-0.06033679,0.009232356,-0.048299525,-0.028859196,-0.042572822,-0.058151186,-0.03549885,-0.024256807,0.06213084,0.030687602,0.0038380222,-0.058877066,-0.047529474,-0.019400718,0.012666168,0.037471462,0.0072683836,-0.026911672,-0.006892,-0.029590806,-0.007655476,-0.04238471,-0.014894213,0.01436252,-0.011522504,0.055624638,0.0345782,0.03374061,-0.0025356088,0.05699438,-0.014183819,-0.0028453986,0.068087265,-0.07186789,0.07289422,0.05982985,0.029119577,0.010926826,0.009022393,0.10587804,0.04765643,-0.113455474,0.07467704,0.048078645,-0.0006374775,-0.060011297,0.023670467,-0.008437087,-0.009964088,0.019883508,0.06048277,0.028947618,-0.02235331,0.12719597,0.020493368,-0.05250026,0.015929228,-0.0134761995,-0.00032885326,-0.055089083,0.07527123,0.015067789,0.05101125,-0.000117375384,-0.021792771,0.011527094,-0.035561327,-0.03784642,-0.08246871,-0.05632231,0.029632045,0.13490881,-0.07482499,-0.092886254,-0.04214594,-0.033366352,-0.027408037,-0.023188546,-0.02128247,-0.049770847,0.07030893,-0.01156247,0.020930292,-0.08584181,-0.03395659,-0.03524542,0.047516316,0.028270148,0.023373425,1.0527974e-32,-0.060055815,-0.062491097,-0.066841654,