INSERT INTO book_pages (page_number, section, content, embedding, inserted_at, updated_at) VALUES (48, 'Página 48', 'Trata-se, evidentemente, de uma organização rudimentar. Situação tipicamente característica de propriedade e de gerência concentradas em uma só pessoa, o que é comum nos países pouco desenvolvidos economicamente. A departamentalização é mínima, por serem escassos os recursos humanos, embora compatíveis com o potencial físico instalado e as metas de produção fixadas. Não obstante, a empresa funciona, e bem! Seus produtos têm aceitação no mercado, Produção e Vendas entendem-se perfeitamente, as finanças estão equilibradas, a Gerência-Geral não tem de que se queixar... Pensa-se, até, num Plano de Expansão.

Pouco habituados a encarar tais questões num enfoque cibernético, é muito provável que sejamos levados a condiderar inadequada, ao presente caso, a classificação de Beer.

Onde se esconde, uma vez que não se mostra visível, a excessiva complexidade dessa estrutura organizacional?

Ela nos parece de uma simplicidade in', '[0.061164033,0.0415669,-0.08702554,-0.057838913,-0.022419965,0.03521394,0.10094136,0.08623488,0.04186653,0.05835436,0.0859647,-0.05191625,-0.018012125,-0.0045754146,0.036860973,-0.0418217,0.038410578,0.016781872,-0.010506988,0.05743907,0.14207186,-0.05670928,-0.044137865,0.06936101,-0.086161,0.0149926245,-0.017517803,-0.021691851,-0.060048945,-0.057059176,-0.0070744394,0.06871269,0.1282011,-0.053089753,0.029582798,-0.006219137,-0.0011275021,-0.021438656,-0.058621317,0.056384426,-0.050003745,0.00076318154,-0.11885708,-0.07675618,-0.053145062,-0.043019608,0.12471875,0.024493942,-0.013699008,-0.009832496,-0.04516158,0.045071907,-0.110989645,-0.009598708,0.02516784,-0.07660179,0.00029709065,-0.060119126,-0.03409803,0.008565851,0.032104675,-0.014865714,0.0022798786,-0.016924718,0.053719502,-0.01614555,0.0030352378,-0.00083074515,-0.09145535,-0.0004978604,0.07545314,-0.09309468,-0.004767729,0.03801343,-0.018126102,0.10781346,-0.003035685,0.00415045,-0.006763019,-0.06145833,-0.00859887,0.017215842,-0.026126752,-0.0053027687,0.01795683,0.011328365,-0.045259997,0.013185272,0.044024218,-0.012847337,-0.00136723,0.052365735,-0.06686402,-0.05053352,0.04670763,0.016314125,-0.040222727,-0.028956333,0.08129219,-0.061580922,0.06676671,0.033080433,0.0518032,-0.042074133,-0.046597254,-0.011294483,-0.03903622,-0.051421903,0.081628956,0.14957781,-0.08624017,-0.075287476,-0.0877797,0.0064962404,-0.057714976,0.0072411704,-0.04633722,-0.050602976,0.033340577,-0.019881235,0.012442038,-0.041032042,0.05847873,-0.03250809,0.04811701,0.012508187,0.045529485,1.0102855e-32,-0.049822778,-0.0666999,-0.021812718,0.0056865625,0.020496229,0.034056548,0.010894789,0.019033054,0.061359055,-0.014324813,-0.10624056,0.07224216,-0.026333846,0.10554658,0.0868798,0.008068388,0.0126580885,-0.05434647,0.033391226,0.0021090698,-0.03287616,0.029101206,0.04962197,-0.059670907,0.014503007,0.022999827,-0.06911923,-0.021325685,-0.018651493,0.0024612474,0.11356929,0.014639037,0.