INSERT INTO book_pages (page_number, section, content, embedding, inserted_at, updated_at) VALUES (50, 'Página 50', 'rio, nos organismos vivos, aplicável a todos os sistemas, e constitui um princípio básico da Cibernética, decorrente da Teoria Geral dos Sistemas. Explicitando melhor o princípio, diremos que os sistemas artificialmente criados, e a empresa é um deles, contam com maiores possibilidades de sucesso na medida em que imitam os sistemas orgânicos, vivos, cuja secular experiência onto-filogenética não pode ser desprezada.

E essa experiência vem projetando, na tela da História Natural, o desenho animado do processo evolutivo das espécies, cuja motivação é o desejo, insatisfeito, que viceja em todas as estruturas animais que não se encontram ainda, anatomicamente equipadas para a transformação de todos os seus impulsos nas ações fisiológicas correlatas. O instinto, e este é um fato repetitivo, motivado pelo desejo insatisfeito orienta o organismo para a evolução contínua das formas de vida, evolução que se processa "pari passu" e que se consubstancia na modelagem dos órgãos incumbidos de exercer, na economia orgânica, a plenitude das funções reclamadas pelo psiquismo ontogenético, sempre', '[0.0010882949,0.023516066,-0.04609955,-0.042610064,-0.03973285,-0.04682406,0.038158514,0.10139629,0.045797832,0.09435326,0.06027422,-0.038435612,-0.018671533,0.040120784,-0.028678622,0.0021664232,-0.008671783,0.03193156,-0.017250128,0.070038915,0.13088377,-0.041957043,-0.067601755,0.07481309,-0.104784995,0.03000389,0.0007569507,-0.042059764,-0.041878827,-0.053199936,-0.0074118674,0.023253929,0.13591024,-0.045486964,0.03318565,0.031687606,0.03505162,-0.05800926,-0.058752738,0.036402747,-0.09217355,-0.016221797,-0.09116167,-0.049996946,-0.0058307494,-0.067875646,0.034096193,0.010134424,0.0054534287,-0.045747966,-0.08455342,-0.011284522,-0.073843196,0.04810224,-0.013909748,0.008214597,-0.014718756,-0.029307637,-0.021715514,-0.03415326,0.031672534,0.057425726,-0.009859531,0.041626055,0.013704101,0.018370867,0.008961842,0.00037391906,-0.010159163,0.015658654,0.053779915,-0.06711243,0.08489675,0.015277183,-0.017608415,0.069011636,0.0014353975,-0.023003517,-0.06418664,-0.099820755,0.02426567,0.05521645,-0.013315539,-0.054287124,0.016229397,0.011965007,0.0026926233,0.010159983,-0.013587301,0.03529521,-0.013455098,0.03314302,-0.07841949,-0.06192644,0.055171423,0.0063241883,-0.048294812,-0.05117913,0.070963934,-0.027532246,0.018209323,0.038579974,0.010707057,-0.0013440329,-0.011892384,-0.030437678,-0.05186585