INSERT INTO book_pages (page_number, section, content, embedding, inserted_at, updated_at) VALUES (51, 'Página 51', 'pronto a fazer novas exigências.

Na empresa, que, como vimos, imita os sistemas orgânicos, as "Funções Essenciais", concebidas pelo gênio de Fayol, existem sempre, e o seu exercício é assegurado independentemente do fato de possuir, ou não, a estrutura organizacional órgãos destinados a exercê-las. Quando, porventura, ocorre alguma deficiência anatômica, a necessidade faz com que uma organização informal, invisível, superponha-se à organização formal e se incumba de suprir o desempenho funcional no nível mínimo imposto pelo contexto socieconômico no qual a empresa está inserida.

Dessarte, para a Cibernética — repetimos para enfatizar — a pequena empresa, de estrutura organizacional aparentemente simples, é, na realidade, um sistema excessivamente complexo. No âmago dessesistema, pulsando com o frêmito de um coração insatisfeito, a estrutura invisível, ao mesmo tempo em que suplementa o desempenho da estrutura formal, anatomicamente deficiente, cria as motivações que irão suscitar o interesse pelo desenvolvimento organizacio', '[0.007347695,-0.02198728,-0.08704316,-0.045102667,-0.042503674,-0.014506604,0.053546872,0.06511585,0.016315013,0.057208903,0.088577226,-0.100104176,-0.020626979,0.02415853,0.028715746,-0.024582308,0.01898484,-0.004851483,-0.085956074,0.11072049,0.13343343,-0.11484009,-0.061811633,0.07890083,-0.089958064,-0.01457657,-0.042438127,-0.0054326546,-0.06111416,-0.06851328,0.019208824,0.032000225,0.13342656,0.010938734,0.06430113,0.055089343,0.048158307,-0.032576226,0.00056480756,0.037283465,-0.0840961,-0.014024781,-0.104404666,-0.0814454,-0.0011132836,-0.04971701,0.055011377,0.09341814,-0.045621697,-0.038355857,-0.032483034,-0.07471555,-0.033589303,0.031559255,0.025396759,-0.012525148,-0.04366899,-0.036388155,-0.03463376,-0.015914895,0.005180854,-0.0034132856,0.025914395,0.009984976,0.015600578,-0.026074752,-0.0063521904,0.0037304251,-0.04539821,0.0121923,0.059860617,-0.1079439,-0.046703864,0.07269366,0.0069720536,0.07953421,-0.012901519,0.01685553,0.0141779445,-0.07547945,0.07087518,0.070737235,0.018061744,-0.0032182855,0.011821969,-0.02082459,-0.015730463,-0.00036892854,0.032497656,0.0008125789,-0.07887509,0.049328633,-0.07772482,-0.038102783,0.03219123,0.020538734,-0.01859979,-0.059927974,0.03278266,-0.023802824,0.03486305,0.021970566,0.040812247,-0.05709406,-0.047612563,-0.04761608,-0.03125651,0.0022575816,0.04618245,0.15219001,-0.10493571,-0.07097284,-0.09630886,-0.048104383,-0.021522267,0.013228719,-0.018508362,-0.049260117,0.114390165,-0.10571602,-0.0068360204,-0.012115626,0.056337256,-0.056916,0.06670679,0.0052980073