INSERT INTO book_pages (page_number, section, content, embedding, inserted_at, updated_at) VALUES (64, 'Página 64', 'gia, dá-se a este processo o nome de HOMEOSTASE. A cibernética absorveu o vocábulo com a mesma acepção.

Algumas considerações, interessantes, podem ser feitas em torno deste primeiro exercício cibernético de regulação e controle.

O sistema é aberto, pois as condições pré-existentes (de antes da perturbação), foram modificadas mediante a inclusão de coisas novas, captadas do universo exterior ao sistema:

- novo "design" do item crítico, que implica uma série de transições em Produção tais como matrizes, ferramentas, materiais diversos, etc.;

- nova política de vendas, que implica a demissão e contratação de funcionários, modificação na propaganda, na rede de comercialização e distribuição etc, que representa transições em Vendas (Departamento da Empresa).', '[-0.00866543,0.05658914,-0.10459346,-0.069808766,-0.026686605,0.016781267,0.0030927353,0.087286815,0.012352754,0.088731825,0.004674057,-0.038663838,0.012424332,-0.03795523,-0.0005620434,0.0052234586,0.027134469,0.022000069,-0.02278347,0.06215871,0.14789523,-0.029875094,-0.0527746,0.09411851,-0.07990726,0.0644163,-0.010981437,0.0027489096,-0.027295385,-0.081339225,-0.017910564,0.05233785,0.0964668,0.00030257474,-0.017189419,0.03972517,0.033568077,-0.04285319,-0.004828848,0.065056846,-0.09643268,-0.00402136,-0.06613291,-0.07511277,0.00072413037,-0.030990131,0.026555073,0.0053939926,-0.061460234,-0.046745148,-0.08675312,-0.029564561,-0.04808541,-0.021486234,0.04493647,-0.017054569,0.021829074,0.0035616136,0.03439181,0.007112982,0.06329269,0.003534669,-0.035963617,0.043842077,0.030355314,0.006773017,-0.04355395,0.023613954,-0.027000906,-0.013810922,0.07299491,-0.10323063,0.026781792,0.05684243,0.016717348,0.05063162,-0.0054188394,0.020039845,0.030773845,-0.118051864,0.04925623,0.04405599,-0.019387437,-0.03632432,0.010666068,0.011991383,-0.015673077,-0.021531729,0.031547584,-0.003317005,-0.013503266,0.014312035,-0.03885498,-0.046270136,0.02385192,-0.040526953,-0.040962078,-0.050103884,0.08996912,-0.0024695352,0.038780652,0.038097225,0.01710049,0.013080654,-0.090579405,-0.04305976,-0.0020564098,-0.012999044,0.0016128068,0.14056678,-0.102726266,-0.052017942,-0.12565902,-0.060269132,-0.03821098,-0.04902556,0.012159825,-0.026509233,0.049700063,-0.0077169454,0.011538759,-0.09439514,0.044237845,-0.08808207,0.073052526,0.0028198247,-0.005518376,8.603632e-33,-0.06316115,-0.03263289,-0.050646853,0.04471526,-0.0075415815,-0.039951563,-0.017421426,0.008662298,0.051351592,0.048481368,-0.036394984,0.11616126,-0.021317137,0.10257191,0.13573962,-0.020964678,0.051228378