INSERT INTO book_pages (page_number, section, content, embedding, inserted_at, updated_at) VALUES (67, 'Página 67', 'Figura 5 — PRAXEOGRAMA OPERATÓRIO DO NOVO SISTEMA

> **[Figura 5 — Praxeograma operatório do novo sistema: diagrama com quatro blocos dispostos em quadrado. No canto superior esquerdo, bloco "PRODUÇÃO"; no canto superior direito, bloco "GESTÃO"; no canto inferior esquerdo, bloco "ESTOQUE"; no canto inferior direito, bloco "VENDAS". Setas sólidas e tracejadas indicam o fluxo entre os blocos: de GESTÃO para PRODUÇÃO (seta tracejada e seta sólida apontando para a esquerda); de PRODUÇÃO para ESTOQUE (seta sólida e tracejada apontando para baixo); de ESTOQUE para VENDAS (seta tracejada e seta sólida apontando para a direita); de VENDAS para GESTÃO (seta sólida e tracejada apontando para cima).]**', '[-0.025759097,0.01899416,-0.05434508,-0.12172288,-0.09186201,0.0030425799,-0.031946335,0.08982946,-0.030311117,0.05598171,0.06896345,-0.06353948,0.02092551,0.018515281,0.021617932,0.003098596,0.04868955,0.015674071,-0.013231844,0.053073507,0.19989707,-0.08876748,-0.07923121,-0.0034591337,-0.00331149,0.014300145,-0.026341483,0.063591756,0.012248716,-0.06743146,-0.061503675,0.03537842,0.038857155,0.017458232,0.017488994,0.0054451684,-0.023130946,-0.031208714,-0.060702663,0.053835634,-0.069599375,0.013697117,-0.0519985,-0.06171055,0.060928427,-0.028077574,0.0058526024,0.049132,0.040403184,-0.097203314,-0.096388556,-0.002591937,-0.09228196,0.004441379,-0.043960396,0.0025735302,0.056468487,-0.04471078,0.04311631,-0.010709595,-0.07831026,-0.017663758,5.7717625e-06,0.02020925,0.10313148,-0.023094561,-0.044557136,0.05889485,-0.07107736,0.08493136,0.026739266,-0.015641933,0.030331621,0.024608359,0.021044355,0.085724555,0.026431544,0.00050509186,-0.03512225,-0.17282626,-0.04820707,0.02036479,-0.06295247,-0.022888133,-0.0006782351,0.041986916,-0.07755238,-0.042221457,0.04719098,0.008846565,0.050400924,0.04756156,-0.07074434,0.039482664,0.004780882,0.05049029,0.0028508622,-0.015621359,0.03471633,-0.04216624,0.060236797,-0.07316659,0.021088911,-0.038536225,-0.101143904,-0.077114694,0.061182573,-0.02999524,-0.01642507,0.0227232,-0.06622095