INSERT INTO book_pages (page_number, section, content, embedding, inserted_at, updated_at) VALUES (83, 'Página 83', 'te, (converge para a incerteza 1 / 1 = certeza), infinita, cuja lei de formação consiste em dividir os termos sempre ao meio.

A sucessão, por sua vez, nos mostra que:

— o primeiro termo mede a entropia mínima do sistema, isto é, sua condição mais energética, que ocorre quando a incerteza reinante é a maior possível. Na medida em que a incerteza vai-se reduzindo, o sistema consome informação (negentropia ou energia), e a entropia vai aumentando:

— a lei de formação dos termos da sucessão, que é condicionada pela lógica de decisões binárias, cujo operador é um heurístico, prescreve um algoritmo-solução cujo número de termos é o logaritmo na base 2 da variedade do sistema;

— como a certeza é o inverso da variedade (ver nota 17), podemos representar a certeza, em função da entropia, segundo o modelo matemático: Log₂ (CERTEZA) = Log₂ (1 / VARIEDADE) = menos Log₂ VARIEDADE;', '[-0.022232812,0.00020163415,-0.04452656,-0.033669397,-0.06952443,-0.0060321908,0.004672431,0.06481565,0.013518238,0.07768543,0.08905716,-0.032575145,0.027366553,-0.034260485,-0.03099747,-0.013250503,-0.017949896,0.004468454,-0.03034982,0.07751395,0.17049639,0.009179785,-0.076828286,0.08598097,-0.0928486,-0.014293214,-0.08969879,0.06702066,-0.023643399,-0.07487521,-0.005460848,0.013341018,0.02412353,0.023039564,0.029832952,-0.0125516355,0.0010673625,-0.038871806,-0.050640356,0.06491546,-0.10772531,0.015062598,-0.08633773,-0.03655637,-0.00890672,-0.075625025,-0.03805541,0.044319797,-0.017790768,-0.06944092,-0.10147323,-0.0034942091,-0.0276102,0.019446097,0.0006765623,-0.035105422,-0.040829856,0.0036674875,-0.026308522,-0.05033287,0.03804704,0.013600834,-0.007322199,0.022311486,0.04314969,0.008989228,0.033478566,-0.056776386,-0.011536633,0.06805853,0.009092185,-0.08233708,0.027512904,0.0417359,-0.00084740395,0.059266534,0.03646045,-0.00048496734,-0.0026929355,-0.06680664,-0.0026461848,0.04143452,-0.027017921,-0.08348811,0.0005612255,-0.013412585,-0.005252083,0.019306783,0.10267507,0.009451426,0.003438282,0.000332697,-0.06887609,-0.055470034,0.09566641,-0.0028202399,-0.0033799487,-0.039370514,0.0628913,-0.056898993,0.09896172,0.02958655,-0.015005234,-0.0014139351,-0.02163076,-0.027252804,0.028072463,-0.04531558,0.080760606,0.09790467,-0.05762715,-0.074126415,-0.05057805,-0.0028001855,-0.07984781,0.0176963,-0.013180468,-0.05100354,0.068817735,0.01271134,0.04889823,-0.06187306,0.011139337,-0.020446915,0.044724192,-0.043535456,-0.01795656,8.408521e-33,-0.041025452,-0.033781823,-0.019011935,-0.022892693,-0.0034162956,0.090876676,-0.093656,0.059745833,-0.019201778,0.039498523,-0.10075616,0.11408221,-0.009582405,0.048180934,0.09294212,-0.061735686,0.039160114,0.050786667,-0.