INSERT INTO book_pages (page_number, section, content, embedding, inserted_at, updated_at) VALUES (63, 'Página 63', '<u>Seta nº 4</u> — indica que Estoque recebe de produção o item crítico, redesenhado, e o repassa para Vendas;

<u>Seta nº 5</u> — indica que Vendas recebe de Estoque o item crítico, redesenhado, e dá o reajuste final nas modificações a introduzir na política de marketing.

<u>Seta nº 6</u> — indica que Vendas reintroduz no mercado, com a nova política de marketing, o produto redesenhado.

<u>Seta nº 7</u> — indica que Vendas informa à Pesquisa o comportamento do mercado em termos de aceitação do novo item (estatística de vendas).

As setas, pontilhadas, indicam que o ciclo prossegue, com a mesma metodologia, até que a perturbação seja eliminada, recuperando-se a meta de vendas.

O sistema atingiu novamente o equilíbrio, apesar das perturbações exteriores que o afligiram em dado instante. Em fisiolo', '[-0.042455696,-0.018310571,-0.12849358,-0.051695473,-0.015635699,0.045243457,0.050500363,0.079398476,-0.013016982,0.03342484,0.09650867,-0.03646349,0.041875765,-0.066582516,0.02674187,0.018472584,0.07585343,0.052816577,-0.013467286,0.020519784,0.10473326,0.0033848966,0.016385164,0.09466782,-0.08424025,0.025917018,0.01750692,0.07427062,-0.05675562,-0.086713344,-0.009713464,0.041521102,0.09808586,-0.074070476,0.034802586,0.034160085,-0.048817273,0.0010430263,-0.039790254,0.054786295,-0.02995958,0.022779701,-0.10557757,-0.047337566,0.022682788,-0.028719068,0.06814568,0.097312555,0.038234405,-0.026886463,-0.039972473,-0.024493475,-0.13522777,-0.05732021,0.014605886,-0.027991667,-0.04836592,-0.008691009,0.02719382,0.0352393,0.038266417,-0.029874565,-0.0516987,0.017658195,0.02806299,0.014149113,-0.044926245,0.01965788,-0.102455765,0.06392806,0.07025504,-0.054493736,0.040529672,0.010823434,-0.027878758,0.04642867,0.08689431,-0.04415536,-0.03096696,-0.06292957,-0.050315518,0.02964806,-0.015191778,-0.08427289,-0.014786583,-0.03235996,0.011409848,-0.022658633,0.073501445,-0.00081704813,-0.023267085,0.034188364,-0.089968435,-0.01916417,0.00065013824,0.004171165,-0.03309187,-0.01254532,0.096208185,-0.005460041,0.09379161,0.040988352,0.0018104628,-0.08161803,-0.11898688,-0.067104414,-0.0054740165,-0.011818364,0.030527845,0.1375244,-0.10582752,-0.0645206,-0.08843084,-0.033358835,-0.071927644,-0.0107911695,-0.03364289,-0.06859431,-0.0040319273,-0.058734737,-0.0046520107,-0.041979678,0.09002838,-0.07980783,-0.0013575777,-0.006664988,0.022377541,6.3457836e-33,-0.097385235,-0.06902104,-0.03474499,0.021254828,0.03397474,0.038306203,-0.053130876,0.051057037,0.024972776,0.018577287,-0.0075340853,0.08638017,-0.055292152,0.07313159,0.122697905,-0.0062092813,0.047656752,-0.014446119,0.005642699,-0.039110698,-0.045198496,0.036142904,0.044508453,-0.07357435,0.03568617,