INSERT INTO book_pages (page_number, section, content, embedding, inserted_at, updated_at) VALUES (107, 'Página 107', 'os da História Natural escondem-se sob a poeira de dezenas de milhões de anos.

Toda esta digressão foi feita para ressaltar uma importante condição dos sistemas artificiais — especialmente a EMPRESA — que contrasta, nesse particular, com os sistemas orgânicos: as perturbações ambientais, salvo os grandes cataclismos, não afetam, drasticamente, as espécies; antes, mesmo, excitam-lhes o funcionamento do mecanismo adaptativo, queimando algumas etapas da consecução, a longo prazo, do binômio evolução-mutação. O mesmo não ocorre, entretanto, com a empresa, pois, dela, quer-se adaptação a curto prazo, com respostas, às vezes, até mesmo antecipativas. Isto é, não podem mudar com a serenidade e a fleuma dos organismos vivos; têm de projetar, na tela do presente, a sua resposta — mutação rigorosamente certa — sob pena de se verem alijadas do painel do futuro.

Agora, estamos mais capacitados para diagnosticar a "causa mortis" de nosso modelo cibernético de administração industrial: "disfunção de SG, caracterizada por uma manifesta incapacidade de adaptar-se às condições ambientais adversas, sucumbindo à entropia alimentada pela variedade proliferante"....', '[-0.010436962,0.01790646,-0.052249458,-0.008167277,-0.027648795,-0.029948168,0.034339763,0.07470463,-0.015505616,0.09810197,0.04560497,-0.035258517,-0.051047336,0.05090722,-0.048913464,0.07268386,-0.0058421497,0.087278664,-0.022730041,0.087284364,0.14523639,-0.043319296,-0.017774075,0.057785977,-0.0882281,0.036819294,-0.06854015,0.022037107,-0.07900227,-0.067553215,-0.028486028,0.103389,0.13197155,-0.02869761,0.050204262,0.05763412,0.043372698,-0.05340887,-0.011813433,0.053212106,-0.0717575,-0.003045763,-0.050547313,-0.07591824,-0.016009934,-0.053237226,0.0886119,0.058214687,0.028165786,-0.02710794,-0.06778663,0.0041257553,-0.09824958,-0.01895342,-0.005449293,-0.04683876,-0.0017346028,-2.347492e-05,-0.0008572944,-0.02342249,0.0064074337,0.018267952,0.00040195876,0.065897614,0.029279672,-0.0069498005,-0.060184304,0.03199457,-0.070197195,0.030179102,0.05099758,-0.09687585,0.00066870434,0.02902917,-0.012320774,0.12619025,0.03852518,0.05221941,-0.03343275,-0.10309057,0.07545798,0.04117266,-0.015549236,-0.07278282,0.018268544,0.033652857,-0.013078183,-0.0070784558,0.09235113,0.024745809,-0.041241918,0.0038061673,-0.087903336,-0.047634553,0.0551047,-0.029905396,-0.016697856,-0.03167649,0.028588863,-0.012316519,0.08190997,0.034046896,0.006091891,-0.034029327,-0.0359202,-0.031630814,-0.07021323,-0.03152639,0.0433548,0.11119895,-0.09363778,-0.049014162,-0.062114663,-0.023661964,0.0064810887,-0.02160884,-0.05138665,-0.056541137,0.044796243,0.0045274966,0.016602475,-0.041510515,0.0055831117,-0.050497875,0.03947618,0.007953341,0.0042571533,1.1079969e-32,-0.043700945,-0.016324528,-0.033123966,0.007382026,0.050439514,0.00678641,-0.021076817,0.03976943,0.012392721,0.019732453,-0.094