INSERT INTO book_pages (page_number, section, content, embedding, inserted_at, updated_at) VALUES (70, 'Página 70', 'deira: estas últimas relutam em aceitar a mensuração das informações, como o quer a acepção cibernética do termo, habituadas que estão em quantificar suas variáveis com valores aferíveis objetivamente através de modelos matemáticos canônicos.

Entropia é palavra composta de um prefixo latino e um radical grego: do Latim: "en" que significa "passagem para um estado ou forma", e do grego "tropos", que significa "volta, giro, mudança". Etimologicamente, portanto, a palavra tem a acepção de volta a um estado, ou forma, pré-existente (se não existisse um estado anterior, não haveria volta)...

O conceito encaixa-se, com perfeição, no princípio geral da degradação da energia que é consequência do Princípio de Carnot: "em um sistema isolado, as transformações de energia tendem a realizar um equilíbrio térmico estável, em que se torna impossível qualquer fenômeno". Ou seja, o calor, em um sistema isolado, satisfaz uma de duas condições mutuamente exclusivas: está igualmente distribuído por todas as regiões do', '[-0.033026997,-0.0023040432,-0.06381649,-0.034343336,-0.09045421,-0.026675606,0.04110551,0.09088731,0.031166423,0.07067205,0.083782196,-0.013885,0.010458366,0.036875274,-0.0009795977,0.009300456,0.032599874,0.036276583,0.04556569,0.11028837,0.16329506,-0.047739204,-0.053157073,0.070824206,-0.060604133,0.074925356,-0.022685312,0.050231937,-0.09616224,-0.040633943,-0.03309387,0.07562318,0.07358842,-0.07218636,0.028852198,-0.016410414,0.001040183,-0.03221814,0.034813073,0.0194514,-0.06267404,-0.012924056,-0.0987194,-0.006167547,0.039882626,-0.082414456,0.06600201,0.07059169,0.022503756,-0.07294886,-0.025839778,-0.026350232,-0.032094564,-0.03898064,-0.048181325,-0.07385363,-0.06422619,-0.02440232,0.03979262,-0.0011767896,0.004430183,0.013515687,0.01791067,0.101685196,-0.03451223,-0.017493965,0.05750908,-0.025257908,-0.06246625,0.0771723,0.02583804,-0.057447016,-0.000865537,0.0074127056,-0.04423206,0.15157692,0.023911236,0.025764234,-0.07037241,-0.11803492,0.0981955,0.05901706,-0.0068993596,-0.0067692515,0.0343394,0.059116267,0.035795487,-0.04001576,0.027315049,0.005397958,0.0043169716,-0.010094678,-0.044072572,-0.08828147,0.04560693,-0.03640926,-0.013900976,-0.029351303,0.054552145,-0.01075175,0.08336767,-0.0069823735,-0.03247273,-0.057082426,0.008589327,0.00889227,0.0036889268,-0.10359671,0.09612079,0.0950977,-0.04459408,-0.056537446,-0.106987216,-0.03312373,-0.05260903,0.01980112,0.023408579,-0.049789656,0.08593594,0.010406221,-0.039259832,-0.0695111,0.049793158,-0.009324527,0.07432088,0.0138950115,0.008157746,8.281289e-33,-0.022872066,-0.029059272,-0.