>     - **Ramo sim → "<7"**
>       - **Ramo não → "<3"**
>       - **Ramo sim → ">3"**
>         - **Ramo sim → "<5"**
>           - **→ "= 4" — DECISÃO NA CERTEZA**
>         - **Ramo não → ">5"**
>     - **Ramo não → ">7"**
>   - **Ramo não → "espada"**
> ]**', '[-0.001552228,-0.0082876375,-0.06339784,-0.05931654,-0.13788715,0.004100485,0.0020627032,0.06553854,0.006574759,0.036156267,0.10084085,-0.055601705,0.00036163334,-0.0018102278,0.046800602,-0.008460326,0.0319682,0.0372166,-0.031173142,-0.08324607,0.1517403,-0.013160727,-0.05186434,0.054509457,0.023030162,0.04614326,-0.023069102,0.058369543,-0.03880149,-0.039060332,-0.055363998,0.07078721,0.13847953,-0.047916055,-0.01569649,0.00010057685,-0.07634576,-0.07986101,0.015326913,0.077406034,-0.05855956,-0.013237697,-0.031285938,-0.032213207,0.037786722,-0.026099265,-0.045172542,0.06480784,0.08692123,-0.033119522,-0.080185905,-0.0056714523,-0.074955456,0.025358232,-0.06563623,-0.051202,0.03365447,-0.0771444,0.08202124,0.058291286,-0.033144526,0.07451246,-0.030410007,0.03261594,-0.039437626,-0.04738052,-0.08860029,0.04060419,-0.01201242,0.08078818,-0.049210075,-0.031932715,0.08073278,0.0976934,-0.12969421,0.030232772,-0.02282474,-0.042064283,0.023381053,-0.116971724,-0.012105265,-0.011728181,0.04268791,-0.06730125,-0.020140316,0.043285936,0.0088100685,0.059672326,0.057497725,-0.06544074,0.08067556,0.052087463,-0.07608331,0.01724838,-0.043070685,0.019149726,-0.030504113,-0.077999696,-0.062206287,0.015853118,0.08663496,0.025939986,0.03350591,0.001297152,-0.092267856,0.005109792,0.07253635,-0.01154339,0.0015069635,-0.008230971,-0.114218175,-0.04528632,0.04446818,-0.043820858,-0.10989529,0.014569793,-0.00371171,-0.077332616,-0.0059051476,0.02259425,0.025597319,-0.0413024,-0.031836342,0.0308737,0.00080947956,-0.064261794,0.011965155,1.951572e-33,-0.06515126,-0.052311387,-0.0015741802,5.612663e-05,0.0641098,-0.015329656,-0.09107451,-0.09966141,0.0067534833,0.081951335,-0.07690446,-0.058270194,-0.024745159,0.014302945,0.03970754,0.018249417,0.071200415,0.00065952487,-0.018442865,-0.034192387,-0.03922461,0.0661554,-0.018266859,-0.030693762,0.012101487,0.1591153,-0.011644012,-0.09514234,0.02340635,0.046044443,0.0049664243,0.011831069,-0.05471809,-0.023449495,-0.04190989,-0.01