INSERT INTO book_pages (page_number, section, content, embedding, inserted_at, updated_at) VALUES (93, 'Página 93', '> **[Figura 11 — MODELO CIBERNÉTICO (simplificado) de Administração Industrial: diagrama com quatro blocos interligados. No topo à esquerda, "Universo Exterior" com setas bidirecionais para baixo conectando ao bloco "Sistema Físico". Do "Sistema Físico" parte uma seta à direita para um marcador circular com ponteiro (indicador "O"). Do marcador saem setas para baixo ao bloco "Controle" e deste para a esquerda ao bloco "Regulação". A "Regulação" conecta-se de volta ao "Sistema Físico" com seta para cima. Os blocos "Regulação" e "Controle" estão unidos por uma barra inferior rotulada "Sistema de Gestão". Do marcador, uma seta tracejada sobe à direita e retorna horizontalmente tracejada à esquerda com o rótulo "Informações", conectando ao "Universo Exterior".]**', '[-0.04413974,0.006060608,-0.10586597,-0.07255554,-0.06334679,-0.0072103757,-0.062165104,0.11394028,0.018966885,0.032927133,0.06127127,0.006524207,0.01667955,-0.0049404684,0.007319389,-0.056706898,0.029658685,0.012102227,-0.031232307,0.057829194,0.16436455,-0.09532147,-0.061133984,0.00077247596,-0.13410528,0.026601817,-0.013417202,-0.005290496,-0.037065968,-0.1076555,-0.050536368,0.060785357,0.078118704,-0.028113425,-0.034046285,-0.03418874,0.07122405,-0.026090585,-0.011615281,0.08261434,-0.09331083,0.035372946,-0.02740022,-0.033762004,-0.0043895068,-0.019796818,0.036599826,0.0042396593,-0.024150182,-0.089067526,-0.09965739,-0.020473609,-0.04692971,0.040108565,0.0020005794,0.030525994,0.03956817,-0.01804198,0.073726326,-0.024981521,0.017509332,-0.035368793,0.018367166,0.046807177,0.040793125,0.020896181,-0.0333688,0.03196944,-0.015862973,-0.0005890831,0.017492235,-0.043662034,-0.009457605,-0.008792015,0.009950231,0.06755042,-0.017092807,0.07124223,0.007886089,-0.16463624,0.015589831,0.045127332,-0.03528916,-0.01939079,0.028680742,0.002090955,-0.011079783,-0.021004066,0.09452685,0.046946388,0.06