INSERT INTO book_pages (page_number, section, content, embedding, inserted_at, updated_at) VALUES (92, 'Página 92', 'A figura 11 apresenta um modelo, propositalmente simplificado, que utilizaremos para o nosso primeiro exercício de pilotagem. Os blocos que o constituem (trata-se de um sistema artificialmente criado, uma empresa) já nos são, de certa forma, familiares. Há dois conceitos, entretanto, novos, sobre os quais faremos ligeira abordagem: variável de ação (VA) e variável essencial (VE), também conhecida como variável crítica.

A dona de casa abre seu livro de receitas e lê, com atenção:

Bolo econômico: Ingredientes: 3 xícaras de açúcar, 3 ovos, 1 colher de sopa de fermento, 2 colheres de manteiga, 1 copo de leite, preferentemente "in natura"; bater as claras, em neve, até que atinjam o máximo volume; colocar os ingredientes na seguinte ordem: açúcar e manteiga (bem misturados), gemas, demais ingredientes, reservando as claras em neve para o último lugar. Forno bem quente; vigiar, entretanto, para que não queime a massa. O bolo deverá apresentar-se corado por fora e cozido in', '[0.0059400806,-0.018531058,-0.104349814,0.004506046,-0.07961513,0.07242354,-0.040481705,0.10955158,-0.026005665,0.05645413,0.08923835,-0.033367306,-0.0048697703,-0.038442105,0.0023135731,-0.034523174,0.11653608,-0.020980345,-0.057571817,0.022109373,0.12929899,-0.017365161,-0.07282425,0.03964885,-0.0474311,0.04714051,-0.0010223665,0.043461576,-0.020649236,-0.13528818,-0.007361243,0.08072638,0.11583633,-0.074467175,-0.010809616,0.0026553131,-0.00025575646,-0.07973533,-0.019425588,0.03308902,-0.039752763,0.011928011,-0.043168645,-0.046079457,0.062211774,-0.014142424,0.028076878,-0.011808752,0.028348986,-0.029652972,-0.093121335,0.011819255,-0.04681939,0.008228749,-0.064597026,-0.020947441,-0.0038944695,-0.036401454,-0.018086378,-0.022455802,0.020066036,-0.00058383506,-0.023201594,0.046060305,0.06048068,-0.051248763,-0.046273474,0.007408152,-0.07827081,0.017934853,0.05126843,-0.06430235,0.0589597,-0.023357086,-0.024692472,0.0803741,0.06082005,-0.031092262,0.014562973,-0.08995536,-0.006727945,0.043857984,-0.027810462,-0.016400913,-0.03429623,-0.025334766,0.014372846,-0.037427388,0.052262895,0.024483154,0.033243697,0.050255295,-0.08904501,-0.030089628,0.032829832,0.05100613,0.0034199834,-0.039135505,0.028187169,-0.0004019867,0.033330757,0.041389104,-0.0007206125,-0.04642456,-0.053874098,-0.03164215,0.034851912,-0.03977911,0.060332086,0.12201781,-0.1370053,-0.036309075,-0.100531526,-0.04847252,-0.039951846,0.006544105,0.031308617,-0.09524452,-0.015443827,-0.06618001,0.030986872,-0.