INSERT INTO book_pages (page_number, section, content, embedding, inserted_at, updated_at) VALUES (123, 'Página 123', 'Por força do princípio da gestão — controlador e controlado devem pertencer ao mesmo sistema — o especialista situa-se intra-sistema. E a recíproca, é verdadeira? Isto é, fora do sistema situar-se-á o generalista?

O assunto merece exame cuidadoso. Voltemos à discussão em torno do papel de controller e da disfunção que costuma ocorrer por sua atuação fora dos limites que lhe são inerentes, pois, aí, encontraremos exemplo sugestivo de aplicação do princípio da especialização do controle.

Familiarizados, que estamos, com o papel a ser desempenhado por controller, sabemos que o dever funcional lhe impõe a obrigação de conhecer, com exatidão, as possibilidades e limitações de todos os departamentos da empresa, mas não exige, dele, nem seria necessário exigir, profundo conhecimento da dinâmica operativa de cada departamento. Controller é, portanto, um generalista. Vejamos, agora, sua posição, relativa, no sistema empresarial, e, também, a relatividade de sua condição de generalista...', '[0.02377546,-0.0003091587,-0.092285305,-0.02737555,-0.07809875,0.0031333575,-0.00014154242,0.08931061,0.07550549,0.08819535,0.093280435,0.0024092465,0.017998502,-0.041617323,-0.0008702234,0.019734036,0.02217127,-0.017064922,-0.0083137555,0.07809609,0.14835462,-0.05010065,-0.061960768,0.06385697,-0.15160017,0.0030986883,-0.037843347,-0.028102653,-0.0669102,-0.11253407,-0.065392785,-0.033623688,0.12920217,-0.021893589,-0.00028216213,0.031156996,0.038573105,-0.06581576,-0.01052024,0.024113655,-0.08110844,0.0049536047,-0.07850481,-0.06372183,-0.0029157344,0.020012842,0.027638778,0.04278073,-0.052358504,-0.08294629,0.010426891,-0.039014902,-0.0040908484,-0.039738912,0.018920194,-0.08982996,0.019858122,0.0013139024,0.022583202,0.017521773,-0.021983944,0.044586223,-0.029837148,0.03450092,0.0063852663,-0.012019511,0.030864675,-0.02253495,-0.05807502,-0.008072533,0.033398222,-0.083721176,0.044794545,-0.0003388104,0.05277986,0.042115714,-0.018592773,0.05964222,-0.01042002,-0.114593215,0.11749866,0.080336295,-0.06101273,-0.009227914,-0.00035593653,-0.02945933,-0.02145241,0.03995386,0.104611404,0.0037410653,0.0048253965,0.01955692,-0.08002645,-0.057010792,-0.0069916463,-0.0060409335,-0.03433844,-0.04668262,0.01517068,-0.057082828,0.07553588,-0.002091619,-0.00054753904,-0.0024925484,-0.013201708,-0.0122886365,0.0042396286,-0.037501317,0.034815315,0.090545565,-0.09680656,-0.07353972,-0.08350522,-0.023638045,-0.012041145,-0.039686467,-0.015884686,-0.03205691,0.033068683,-0.06367432,-0