INSERT INTO book_pages (page_number, section, content, embedding, inserted_at, updated_at) VALUES (101, 'Página 101', 'Recordemos que a variedade de SF condiciona a variedade requerida de SG, e que, nos dois exemplos dados, ficou claro que ela pode alterar-se para mais, isto é, que a variedade requerida é, em última análise, uma variável, pois função de um conjunto afim de variáveis. Isso indica que os sistemas físicos apresentam tendência à variedade proliferante, absorvida de UE na medida em que, este, passa por modificações que extrapolem dos níveis tidos como normais.

Parece-nos que a questão, agora, põe-se da seguinte forma: "se SG tivesse sido projetado (a referência diz respeito, ainda, aos exemplos dados) com reserva ilimitada de variedade, seria capaz de pilotar SF, qualquer que fosse a variedade proliferante absorvida, por este, do universo exterior?...

---

(Continuação da pág. anterior) razão pela qual todos os sistemas são dotados de mecanismos sensórios destinados à captação, o mais aprioristicamente possível, de estímulos aferentes nociceptivos, os quais têm de ser analisados em tempo útil para a formulação de estratégias e a deflagração de ações de defesa do sistema.', '[0.0079862,0.009073144,-0.08429904,-0.03087235,-0.044243667,0.032434173,0.059125837,0.09459509,0.019530145,0.08361798,0.09114052,0.0072618574,0.003073262,0.026686609,0.048736364,0.019222168,0.0129381055,0.0260987,-0.081542306,0.112713724,0.1313706,-0.043526765,-0.04270037,0.0076729883,-0.07816239,0.0053367363,-0.008175946,0.016261121,-0.00023780455,-0.051671363,-0.003592061,0.12560302,0.06750891,-0.039136488,0.035229187,0.012290514,0.01238289,-0.017876873,-0.06255839,0.076566316,-0.07331257,0.045532376,-0.0684981,-0.057163727,-0.038177162,-0.032386906,0.02534723,-0.006781673,0.01064309,0.0029262507,-0.05723228,-0.011682898,-0.10222971,0.044058766,0.029118476,-0.094881766,-0.06902597,-0.011365212,0.0052162753,-0.049925905,-0.027742287,-0.041830584,-0.029841442,0.03430233,-0.0026405146,0.024389368,0.01688856,-0.0128265405,-0.013133731,0.05437026,-0.013852849,-0.026740672,-0.04226308,0.052832633,-0.057182863,0.093527116,0.071292646,0.0040293527,-0.01702932,-0.14605193,-0.030075017,0.06879707,0.013187313,-0.017148223,0.05054888,0.04643056,-0.014029755,-0.025784418,-0.0077099637,0.068035364,0.03429251,0.0020702395,-0.021679375,-0.11664619,0.062382244,-0.0064721173,-0.027684333,-0.10197179,0.11022858,-0.044057917,0.09233152,0.051027834,0.018648986,0.008358329,-0.059986196,-0.032880954,-0.032890674,-0.04064159,-0.009877011,0.11570427,-0.090584576,0.017990174,-0.06293494,-0.054836944,-0.03416929,-0.02925278,0.013321034,-0.043115243,0.008979949,-0.01891811,-0.028505355,-0.032727644,0.05910475,-0.06653038,0.012109802,0.02031939,0.0031919924,9.212821e-33,-0.03152105,-0.047565017,-0.0077361814,-0.028298639,0.050952412,0.06661124,-0.022756012,0.03298973,0.02542