INSERT INTO book_pages (page_number, section, content, embedding, inserted_at, updated_at) VALUES (102, 'Página 102', 'A resposta é, intuitivamente, não! Voltemos a pensar no exemplo da aeronave e sua tripulação...

O tempo apresenta-se bom, as condições de funcionamento da aeronave são normais, os passageiros estão tranquilos. O comandante liga o piloto automático e refestela-se em sua poltrona para ler o jornal do dia. A campainha de alerta soa na cabine: o radar — mecanismo sensório de captação de estímulos aferentes nociceptivos — detecta a ocorrência de turbulências na aerovia, a alguns minutos de vôo. O navegador, analisando o sinal de alerta, informa o comandante sobre a impossibilidade de passar por cima ou por baixo da turbulência. Ela tem que ser atravessada! O comandante retoma os controles da aeronave, pois sabe que o piloto-automático, sob condições meteorológicas mais severas, é ineficiente.

A aeronave atinge a região de turbulência. A tripulação empenha-se, fazendo uso de toda a perícia, habilidade e sangue frio de que é dotada, em neutralizar os efeitos desestabilizadores das fortes correntes', '[0.046912644,0.045421842,-0.07795851,0.018186104,0.034283973,-0.07431792,0.07920773,0.024192201,0.013537494,0.047589887,0.040680755,-0.0690056,0.027068194,-0.011323559,-0.021392288,0.033842597,0.010725601,-0.013574684,-0.015683372,0.047541533,0.10377855,0.040893365,-0.06609745,0.08218758,-0.15539524,0.039725207,-0.008922317,-0.029390696,-0.08963893,-0.03979036,-0.022252474,0.04087067,0.051352452,-0.00028395507,-0.006297194,-0.06332663,0.065333724,-0.018239088,-0.01988663,0.027327027,-0.1175002,0.027418796,-0.076604135,0.0042022485,-0.02735767,0.018454295,0.0027755261,0.035107825,0.020034596,-0.03459661,-0.05271847,0.009468089,-0.043431275,-0.012791453,-0.0033855964,-0.030132309,-0.07386267,-0.05684595,0.051842265,0.008210147,-0.045505438,0.032764744,-0.00041736825,0.033916574,0.0027810798,-0.016650919,-0.058375783,-0.03331047,0.06819379,0.03344989,0.025640901,-0.053865843,0.04381268,0.004155378,-0.048638843,0.018479109,0.029309254,0.008568277,0.012694621,-0.062239017,-0.030098336,-0.066755235,-0.059044752,-0.017656466,0.06474869,-0.00429072,-0.033042353,0.04153579,0.051945962,0.010744427,0.03653446,-0.027820641,-0.10084386,-0.031719137,0.043211482,-0.041197307,0.026266374,-0.051517855,0.017791083,-0.029723562,0.05053083,-0.033918403,-0.01825282,0.055394437,-0.025319431,-0.007991737,0.029863942,-0.08407842,0.058231268,0.097447924,-0.11691457,-0.04323743,-0.0027529453,-0.045805268,-0.072525464,0.0024172391,-0.08104396,-0.062986195,-0.024022881,-0.018135915,-0.023325577,-0.077062614,0.029801333,-0.022816012,0.0700334,0.02544589,0.03308679,8.654557e-33,-0.05076405,-0.0048302636,-0.022965005,-0.0048513254,0.06944581,-0.010568873,-0.05704734,-0.0030782872,0.086747095,0.08718124,-0.10549315,0.0655074,-0.048511554,0.0050595277,0.117172144,-0.011255733,0.01614963,-0.09