INSERT INTO book_pages (page_number, section, content, embedding, inserted_at, updated_at) VALUES (122, 'Página 122', 'sobre a operação, infere-se, naturalmente, que o poder controlador precisa conhecer, perfeitamente bem, o elemento controlado. Daí decorre o princípio da especificidade da gestão, ou da especialização do controle. É certo, portanto, falar em controle contábil, financeiro, de qualidade (aspectos técnicos, da operação), administrativo, etc. Infere-se, também, que o elemento controlador (o regulador) precisa conhecer, igualmente bem, o elemento operado (sistema físico).

Chegamos, finalmente, à figura do especialista, tão mal compreendido e injustiçado, que deu a Chaplin a inspiração de sua obra prima, "Tempos Modernos", que contribuiu, ainda mais, para confundir e disseminar a injustiça em torno do comportamento desse produto aristotélico da cultura ortodoxa.

Pretendemos contribuir, através destas considerações, para colocar o especialista em sua exata posição e para lhe conceder a dimensão que deve possuir, sem excesso nem falta, no contexto das ciências aplicadas.', '[-0.010894205,0.017402124,-0.06327911,0.029857852,-0.03799425,0.013940026,0.021869121,0.06083647,-0.0024714612,0.10589489,0.09640945,-0.025627676,0.030811155,-0.009877637,-0.0214515,0.009160318,0.022159886,0.005618997,-0.004199153,0.07027643,0.08060311,-0.09004287,-0.043731917,0.070012495,-0.13448282,0.011545685,-0.06764589,-0.032579202,-0.026653348,-0.07498676,-0.061878946,0.030886028,0.12829389,0.0071898596,-0.04698822,0.035723723,0.046990547,-0.07195177,-0.0071155606,0.028436216,-0.0912803,0.010211391,-0.06268662,-0.06166061,-0.013452361,0.03779109,0.09358764,-0.0033327492,-0.029590847,-0.06248893,-0.05237053,-0.005640408,-0.022288973,-0.03771726,-0.008978216,-0.021113478,0.055502407,0.021574985,0.05301167,-0.023275087,-0.038684014,0.04130662,-0.059604425,0.06530867,0.02798324,0.06589072,0.02771551,0.028209977,-0.02670138,0.029802773,0.07800445,-0.082376756,0.07284312,0.06339807,-0.016778847,0.024589125,-0.022371609,0.046610758,-0.023729442,-0.116110064,0.036553342,0.0119318385,-0.03093719,-0.10819015,0.022282066,0.039631322,0.002607133,-0.023750674,0.12357238,-0.00022547654,0.006593002,0.04446333,-0.090496585,-0.038865715,0.044280533,0.017703991,0.024885762,-0.012909803,0.08404607,-0.019483253,0.101418674,0.0138483755,-0.047736023,-0.009004834,0.0034842868,-0.05075719,-6.093733e-05,-0.040854152,0.00848184,0.14229691,-0.043919466,-0.089420736,-0.047024664,-0.06049865,0.006357184,-0.010618139,-0.016791897,-0.01709477,0.059334815,0.002124254,0.029995967,-0.07385109,0.05288048,-0.02512287,0.052837502,-0.0009428336,0.007992546,8.5165954e-33,-0.02631287,-0.06352605,-0.076448955,-0.010776676,-0.026714709,0.08944367,-0.018605653,0.05843638,0.010852937,0.021137433,0.0076429844,0.0070427847,-0.08519639,0.018762356,0.11537965,-0.01628357,0.00792101,-0.024720903,0