INSERT INTO book_pages (page_number, section, content, embedding, inserted_at, updated_at) VALUES (119, 'Página 119', 'partamentais, de que resultam recomendações advertências, instruções normativas, enfim, uma enxurrada de papéis, tudo devidamente respaldado pela respeitável chancela da presidência...

O pior é que todo esse esforço, as mais das vezes inútil, cria, inevitavelmente, um clima de tensão e de desconfiança recíprocos entre os departamentos e a alta hierarquia da empresa. Inútil; porque controller, no exercício da disfunção, não pertence ao sistema controlador/controlado, e, consequentemente, não pode agir, em tempo real, sobre as causas de eventuais rupturas das VE departamentais. Ademais, problemas que, de outra forma, poderiam ser solucionados (e, certamente, se-lo-ão) nos níveis departamentais, irão sobrecarregar, inoportunamente e desnecessariamente, a agenda da presidência.

Qual seria, então, a fórmula para resolver, de outra forma, os problemas, a fim de que a hierarquia superior do sistema não fique sobrecarregada com questões que, até prova em contrário, dispensam sua gestão di', '[-0.0011843211,-0.0005558402,-0.05748087,-0.039674684,-0.06502623,0.02067562,-0.0134784235,0.08113025,0.09471368,0.066982,0.10595029,-0.036004,0.06696007,-0.03273135,0.014757937,-0.043958988,0.009408052,0.014264475,-0.03795651,0.063474946,0.13149011,-0.0045551956,-0.091833144,0.041982237,-0.14195085,-0.05083098,-0.03184045,-0.017213345,-0.08449624,-0.12723368,0.023907527,-0.005331231,0.08564204,-0.04956872,0.05018249,0.061198756,0.048159614,-0.051332112,-0.04167508,0.04079795,-0.0971892,-0.014290588,-0.081086665,-0.098498054,0.009796065,-0.039142497,0.00033371698,0.023843318,-0.015262341,-0.020441383,-0.0071047535,0.017127115,0.0022839764,0.0058471225,0.025963195,-0.045954917,-0.04100241,-0.036757533,0.014247602,0.0007028084,-0.024292199,0.037592437,-0.03921413,-0.01491291,-0.018566787,-0.00027889054,0.025474316,-0.036237575,-0.0327519,-0.032731257,0.018040251,-0.1025786,-0.022298917,0.05179682,0.018847175,0.02848566,0.005247229,0.078987055,0.021327823,-0.0963483,0.096271805,0.06943777,-0.03854528,-0.0050684507,0.053792726,-0.02340136,-0.00015363451,0.008716042,0.07555428,0.010761957,0.01803192,0.03446,-0.10140438,-0.053082224,0.023535587,-0.018036095,-0.01723571,-0.021856027,0.04775445,-0.033815645,0.044643726,-0.010106521,-0.05982678,-0.025434308,-0.049306795,-0.014707406,0.019873934,-0.07297243,-0.0033462641,0.08596716,-0.053522695,-0.10558359,-0.10496041,-0.08576459,0.001028244,-0.029297324,-0.05655344,-0.03937205,0.0057222038,-0.08222736,-0.034469668,-0.07943345,0.0479134,-0.023537476,0.049398,-0.0213644,0.043467917,9.181539e-33,-0.021255558,-0.01904576,-0.07824005,-0.00070453214,0.034232803,0.048838917,-0.024825612,0.048090637,0.08440556,-0.003396559,-0.053519033,0.074667364,0.0014023021,-0.009850643,0.10466299,-0.023774786,0.07877513,-0.0067874123,-