INSERT INTO book_pages (page_number, section, content, embedding, inserted_at, updated_at) VALUES (125, 'A Curva do Conhecimento Humano', 'especialistas, os generalistas e os sistemas é de capital importância. Com base no que temos sentido, até agora, em torno da pilotagem dos sistemas, tentemos ordenar algumas idéias a respeito do assunto:

1º - todo especialista é, em certa dose, um generalista, e reciprocamente;

2º - o Índice de especialização aumenta, da periferia para o centro, no modelo circular de pilotagem; e, reciprocamente, o Índice de generalização diminui, no mesmo sentido.

### A Curva do Conhecimento Humano

Existe, dessarte, uma relação funcional explícita, decrescente, entre as variáveis que representam, no mesmo processo de medida do conhecimento humano, os Índices de contribuição do que é específico e do que é geral. Tal relação é passível de representação matemática através de um modelo da forma Y = f (X), de imagem cartesiana como a da figura 16, na qual a envolvente pode ser tomada como a Curva do Conhecimento Humano.', '[0.05000182,-0.0030340557,-0.062077086,-0.028541593,-0.05290617,-0.03108934,0.04497295,0.07567501,0.005032197,0.06549736,0.029751958,-0.06356872,0.008149749,0.0377266,-0.0069534685,-0.09007036,-0.036947284,-0.007792539,-0.011071495,0.13949223,0.18451318,-0.046028107,-0.091514684,0.069856815,-0.09592247,-0.02618626,0.004801822,0.0026393887,-0.062387425,-0.08883236,-0.062482223,0.100834474,0.15438645,0.016094167,0.020494903,-0.009303635,0.013998262,-0.028988453,-0.04502318,0.033691067,-0.073413976,-0.031934332,-0.05213424,0.030077389,0.02460606,-0.024813786,0.041269865,0.010160592,-0.02375392,-0.028198672,-0.072068475,-0.051040586,-0.06134861,0.0066492036,-0.02134538,-0.028509954,-0.013590504,-0.055541698,-0.01788024,-0.029615626,0.055069204,0.006289833,0.016516825,0.072828226,0.032077014,-0.0035409564,0.0013695017,-0.03976339,-0.043136198,0.0017421644,0.039145023,-0.11063884,0.01647451,0.0058828457,0.026599413,0.038703207,-0.01967071,0.05285713,0.052417457,-0.08611321,0.019424984,0.027363498,-0.058414795,-0.01618321,0.026569277,-0.005108836,-0.038790658,0.013833568,0.03711566,0.04564237,-0.010288198,0.031588916,-0.08606524,-0.058005635,0.0013192961,0.052119378,-0.0067355037,-0.017077863,0.07604961,-0.012817748,0.056585055,-0.01654608,0.010349823,-0.019349135,-0.036714893,0.04238276,0.03741268,-0.07132985,0.023017036,0.061078317,-0.12520258,-0.02168836,-0.085515,0.0073741707,-0.026539266,-0.016328843,0.011626949,-0.03517028,0.053705566,-0.06063754,0.034921736,-0.08978841,0.021525163,-0.069322824,0.060126606,-0.02683952,-0.013016074,8.1969616e-33,-0