INSERT INTO book_pages (page_number, section, content, embedding, inserted_at, updated_at) VALUES (130, 'Página 130', '> **[Figura 18 — O Modelo Evoluído. Diagrama cibernético com dois níveis de pilotagem e um componente de Evolução. O Sistema de Gestão (à direita) é composto por Controle e Regulação, conectado ao Sistema Físico (centro-esquerda), que interage com o Universo Exterior (esquerda). Acima, um Objetivo Evoluído (OE, representado por um círculo com ponteiro) recebe informações e está ligado ao bloco Evolução (à direita), que retroalimenta o Sistema de Gestão. O fluxo de Informações sobe verticalmente do Sistema de Gestão ao OE. VE indica as Variáveis Essenciais que fluem entre o Sistema Físico e o Sistema de Gestão.]**', '[0.0082080625,0.04866716,-0.11316714,-0.059150364,-0.031199362,-0.034801025,-0.09585908,0.13676171,0.023339383,0.05709943,0.101953715,0.031950697,0.031368267,0.011911373,-0.035396617,-0.023681866,0.0072586252,0.0022783445,-0.0072311433,0.05533352,0.14054255,-0.051608365,-0.072007775,-0.0106771905,-0.084211856,0.0073566562,-0.0011571542,0.06456501,-0.04731676,-0.11662264,-0.009834724,0.07180105,0.11114771,-0.0051086186,-0.0649005,-0.068090364,0.05548287,-0.06681462,-0.036510535,0.053513527,-0.06464575,-0.029062646,-0.019680135,-0.024889963,0.034664813,0.014137125,0.024230922,-0.013183049,-0.05341931,-0.041452378,-0.08753389,-0.054362442,-0.011141396,0.033766225,-0.016696198,0.031143269,0.009485651,-0.004318938,-0.015221531,-0.008635481,0.050277017,0.037536502,-0.03347955,0.04573756,0.011126682,0.012749064,-0.038328048,0.01863848,-0.039331548,-0.06286084,0.037895713,-0.06283399,0.026826123,-0.0871626,0.003065024,0.084565684,0.012520793,0.07067332,0.067023635,-0.14366549,0.031809915,0.054325514,-0.056933153,-0.011581368,0.0012841123,-0.008491334,-0.058271598,-0.014180588,0.03015909,0.03174472,0.027544573,0.0026778404,-0.038023088,-0.028174413,0.070848495,0.040281147,0.0088586835,-0.13136248,0.037459027,-0.027614452,0.051729966,-0.017464207,