INSERT INTO book_pages (page_number, section, content, embedding, inserted_at, updated_at) VALUES (139, 'Página 139', 'Figura 20 – Sensório Cibernético

> **[Figura 20 — Diagrama do sensório cibernético composto por dois grupos de transdutores e duas placas (sensitiva e motora) interligadas por um retículo anastomótico. À direita, a "placa sensitiva" (parte de frente e parte de atrás) e a "placa motora". Ao centro, o "retículo anastomótico". À esquerda, dois grupos de elementos: acima, "Transdutores de saída (efetores)" com sigla "SIC = sensorial im put channel" ligados à placa motora pelo "MOC" e por "Correntes de impulsos eferentes"; abaixo, "Transdutores de entrada (sensores)" com sigla "MOC = motor out put channel" ligados à placa sensitiva pelo "SIC" e por "Correntes de impulsos aferentes".]**', '[-0.0049927076,-0.057103176,0.03214266,-0.057780165,-0.03965725,0.01789853,0.07764906,0.094791315,0.026768748,0.066047914,0.12732969,-0.051674247,0.023266885,0.067202315,-0.012057124,-0.011050807,0.06674601,0.028596623,-0.049298245,-0.0216325,0.18198869,0.009433645,-0.010163686,0.042864095,-0.1318869,-0.02374977,-0.084729165,0.037385955,-0.09333014,-0.10551013,-0.049725994,0.040316183,0.013540984,-0.09710467,0.029200055,0.0074376157,-0.0059579355,-0.070733115,-0.010010618,0.021140156,-0.049275354,-0.05348461,-0.0049472232,-0.029718146,0.043273695,0.0051002842,0.056630988,0.033844233,0.0063183154,-0.032064736,-0.05938898,-0.06600671,0.00046081693,0.017308917,-0.03355876,-0.04620747,-0.022273315,-0.0023061046,0.084304065,0.0029926659,0.007301371,0.004418606,0.002733713,0.05127394,-0.010177629,-0.026370522,0.0050045443,-0.03726163,-0.016782414,-0.009582627,0.022885159,-0.10001183,-0.015405733,0.04102121,-0.013066803,0.040753044,0.029949648,-0.023219181,0.035066944,-0.09599939,0.019844333,-0.034582295,-0.050820693,0.0079438565,0.019411596,0.029704677,0.03995653,-0.012696313,0.0157351,-0.03739249,-0.06608688,-0.0052837646,-0.102380976,0.02575407,0.02996014,8.195631e-05,-0.056409765,-0.008097056,-0.011226482,-0.03105146,0.07193361,-0.03153701,-0.057483565,0.003932712,-0.12546617,-0.02927097,0.0094248755,0.02593488,0.03854585