INSERT INTO book_pages (page_number, section, content, embedding, inserted_at, updated_at) VALUES (173, 'Página 173', 'A informática constitui um dos principais campos da cibernética aplicada, por isso o informático deve ser, antes de tudo, um ciberneta. E, para atuar na administração industrial, ele precisa ter pleno domínio sobre as informações brutas, ainda não processadas, que transitam "interna corporis". Sem isso — lembremo-nos de que o "brain-trust do modelo neurofisiológico exerce esse domínio, em toda sua magnitude — quebrar-se-ão, fatalmente, os elos da cadeia informática, surgindo a disfunção que tem caracterizado os usos e abusos do computador nas empresas industriais.

Valer-nos-emos de um exemplo real para ilustrar a natureza do que definimos como uma falácia da informática.

O exemplo reporta-se a um curso de extensão universitária, versando sobre o tema:

---

*(Continuação da pág. anterior) missão própria, que deve ser confiada a um informático que conheça a natureza e as particularidades do sistema a ser beneficiado com processamento de dados; 2º — que a falácia da informática se refere à administração industrial.* (Continua na pág. seguinte...', '[-0.010105052,-0.041879132,-0.08839189,-0.05246342,-0.040128484,-0.0079913195,0.048393417,0.059827447,0.043590922,0.07787902,0.032527108,-0.0027262827,0.0019886342,0.019387843,-0.0270369,-0.024422938,0.02984741,0.00081016065,-0.04305617,0.027277282,0.16331355,-0.028668588,-0.07947363,0.011322266,-0.079450764,0.011558134,-0.023451146,-0.08445435,-0.04695433,-0.06438731,0.022722792,0.07102794,0.11948889,-0.014084968,0.0035065047,0.02519058,0.04985668,-0.033030305,-0.021762703,0.03778901,-0.060033493,-0.033017654,-0.024602428,-0.027545495,-0.0100947665,-0.04514833,0.040440455,-0.03191708,-0.047914483,-0.026049996,-0.12381891,-0.03355612,0.00827938,0.037607186,-0.012503455,-0.02931121,-0.00011988514,-0.0018344759,-0.05941116,0.02090156,-0.008772945,0.019867184,-0.0038852133,0.00876244,0.051627796,0.037270047,-0.014737575,-0.045509946,-0.011514806,-0.104756854,0.042818014,-0.04983324,-0.06709738,0.0047601173,-0.034125175,0.07449564,-0.0060685095,0.04616203,0.040068854,-0.1642176,0.046321727,0.12540387,-0.012928108,-0.0082611125,0.032528464,0.050022822,0.0073626055,0.0616567,0.024783384,0.025676563,0.0016837864,-0.023479247,-0.10300933,-0.0011288465,0.022177827,0.005246766,0.004595005,-0.07476381,0.03709538,-0.04934935,0.052193344,0.01221138,0.0015322914,-0.032736383,-0.045672834,0.0058613652,0.0061117243,-0.07037466,0.07111142,0.10228008,-0.07997296,-0.01921355,-0.13986447,-0.06393065,0.01132763,-0.02472126,-0.061649743,0.050476428,0.0638568,-0.05219371,-0.022766598,-0.054246992,0.022149684,-0.048140705,0.051541142,-0.058469854,-0.032508638,1.10417314e-32,-0.08026646,-0.044377055,-0.030334681,-0.00975128,0.03147262,-0.00746721,-0.054615915,0.010642879,0.069572486,0.024948275,-0.106