INSERT INTO book_pages (page_number, section, content, embedding, inserted_at, updated_at) VALUES (198, 'Página 198', 'portante é outra: conhecendo o comportamento de todas as partes do sistema, cujas performances habituais armazena em sua "memória", fornece subsídios à formulação de séries históricas, estatísticas, de níveis de desempenho-padrão, instituídos "a priori", os quais constituem os fundamentos da contabilidade gerencial a ser posta em prática em todos os graus da hierarquia de controle do sistema alpha. É informática, portanto, a sede do SIPCP. A presidência, (com suas assessorias) exerce o papel reservado aos dois níveis mais elevados das hierarquias de controle, que correspondem aos terceiro e quarto níveis de pilotagem, respectivamente evolução e mutação. O vice-presidente executivo e os diretores de departamentos consubstanciam a gestão, segundo nível. Os gerentes de divisão de serviços operam no 1º nível o sistema físico.

O funcionamento do modelo, em termos de estabelecimento de variáveis de ação e de variáveis essenciais, não apresenta novidades. Tem-se a considerar, apenas, que quaisquer dos quatro níveis de pilotagem contam, agora, com um banco de dado infalí', '[-0.0016437486,0.019823415,-0.061906785,-0.0790114,-0.10054343,0.019753203,-0.0455171,0.08609091,0.029972384,0.11507411,0.058140118,0.038332444,0.016924994,-0.005956586,-0.019367725,-0.03358207,0.015421985,-0.0077883685,0.031143583,0.07012245,0.10753308,-0.015198523,-0.016240185,0.0104077235,-0.08321843,0.046104524,-0.053511012,-0.043343402,-0.020315198,-0.059674002,0.0137545625,0.041303948,0.14221446,-0.014991339,0.004641736,0.024444332,0.05820374,-0.029164193,0.017010607,0.042653855,-0.047622208,0.006209738,-0.06798553,-0.05064809,-0.032948446,0.0038669228,0.009161835,0.051816363,-0.018206963,-0.006475141,-0.025384696,0.011331339,-0.0050658407,-0.029597627,-0.013491183,-0.07513445,-0.011414148,-0.0066908677,0.022170132,0.023378562,-0.04954129,0.023034722,-0.06784197,0.013608571,-0.017936144,-0.018750958,0.005875003,-0.0017080813,-0.03404466,0.011499663,0.028745847,-0.047391903,0.028833672,0.003336293,-0.07858661,0.023567487,0.03280784,0.07046869,-0.0146337785,-0.16438521,0.06796923,0.02559602,-0.060894318,-0.030302377,0.031274326,-0.017049583,-0.008626014,-0.0298545,0.06034255,0.01197913,-0.009504754,-0.0009460463,-0.055519406,-0.07131007,-0.005222968,-0.00701183,0.0009029135,-0.024469024,0.052215625,-0.0038162689,0.099174105,0.017477239,-0.040566437,0.011810107,-0.05299902,0.009446687,0.008753477,-0.08093669,0.031984985,0.07555659,-0.073512405,-0.039555743,-0.072668836,-0.050332043,-0.017721867,-0.04629709,-0.035112444,-0.044840716,0.023329843,-0.039074045,0.02224026,-0.082597956,0.07515393,-0.018336402,0.06282328,-0.028667167,0.05390536,4.902085e-33,0.0011617284,-0.06583779,-0.05600608,0.03049543,0.011049205,0.0873038,-0.03512311,0.001856021,0.05597849,0.021025714,-0.04020036,0.065319255,-0.008472392,-0.015855893,0.08