INSERT INTO book_pages (page_number, section, content, embedding, inserted_at, updated_at) VALUES (157, 'Página 157', 'Figura 23 – Modelo Neurofisiológico Cibernético

> **[Figura 23 — Diagrama do Modelo Neurofisiológico Cibernético. Representação vertical do sistema nervoso em corte, com os seguintes níveis hierárquicos, de cima para baixo: "Espaço Extra-Cortical — INTUIÇÃO" (nível 4º — Mutação); "CÓRTEX" (nível 3º — Evolução); "DIENCÉFALOS / GÂNGLIOS BASAIS" (nível 3º — Evolução); "PONTE/BULBO" (nível 2º — Gestão); "MEDULA" (nível 1º — Operação). Ao longo do eixo lateral esquerdo está o "Sistema Parassimpático" e ao direito o "Sistema Simpático", representados por linhas tracejadas. Setas bidirecionais verticais conectam os níveis intermediários. Uma esfera na base representa o corpo operacional.]**', '[0.040713828,-0.027845014,-0.054487772,-0.08624056,-0.08595776,0.020196008,-0.065857105,0.12368711,0.08195951,0.041223917,0.060988285,-0.017385565,0.031007577,0.014476483,-0.027735345,-0.06094693,-0.022276103,0.02216883,-0.036423482,0.108753875,0.17486565,-0.053387202,-0.085256614,0.013420262,-0.07731789,0.011411665,-0.0056400555,0.030609736,-0.008152834,-0.101495154,-0.017503383,0.078891866,0.05198434,-0.016147638,-0.03700613,-0.04478089,-0.003274378,-0.08033495,-0.014976942,0.04194228,-0.053878076,-0.016757812,-0.0067636706,0.03454246,0.031777672,0.034363877,0.01763427,-0.020704579,0.018746167,-0.049314704,-0.10860855,-0.034565534,-0.021586595,0.09231143,0.0135540785,0.017060477,-0.06290264,-0.044567227,-0.004079598,0.016800964,0.03551633,0.03501323,0.036183972,0.019646972,0.0530717,0.021349158,-0.042787418,-0.048620287,-0.08175166,-0.031469684,0.063811876,-0.08160478,-0.051786475,-0.04210301,-0.032861277,0.13892652,0.03721779,0.06567071,0.05144697,-0.1832039,0.03160269,0.13475902,0.0012441708,0.040930085,0.01440265,0.016996015,0.00013425981,0.022955164,0.009501357,-0.0033119658,0.0422096,0.015253854,-0.12262256,-0.038464632,0.04259216,-0.026635334,-0.0057515753,0.0031077485,-0.03193746,-0.03011702,0.083286315,-0.047293738,0.055836894,0.017820122,-0.078637615,-0.010172425,0.063069806,-0.030525424,0.0350892,0.026994338,-0.1246167