INSERT INTO book_pages (page_number, section, content, embedding, inserted_at, updated_at) VALUES (160, 'Página 160', '— em segundo lugar, ensejará a resposta, volitiva, que deflagrará a ação motora, corretiva, através dos efetores;

— em terceiro e último lugar, será objeto de registrona "memória" de Op, enviando-se breve notícia da ocorrência a Ge. Este registro é que faculta a absorção de experiência.

No segundo nível, gestão, as intervenções, apesar de contarem, ainda, com certa autonomia, são, em sua maior parte, deflagradas a nível de consciência. A intervenção, volitiva, de Ge sobre Op ocorre quando estímulos nociceptivos, apesar de reduzidos em sua variedade, conseguem romper o bloqueio sofrido no primeiro nível, atingindo o segundo nível não apenas como informação processada, mas, como ameaça à estabilidade do sistema. Este baluarte deve resistir o mais que puder. Os problemas, internos, de regulação e controle, precisam ser esgotados neste nível, a fim de que Ev possa dedicar a maior parte de seu tempo ao pleno exercício de sua atividade precípua, que é vital para o sistema.', '[-0.03440596,-0.024506913,-0.045114752,0.0016350063,-0.061582007,0.0229163,0.003104499,0.0731015,0.019138694,0.02338127,0.09647307,-0.016822996,0.04284818,-0.0026470064,-0.015415944,0.0070831287,0.06299392,0.026327016,-0.006958157,0.05524058,0.116290726,0.010069088,-0.024027973,0.08307919,-0.103530474,0.085393496,-0.035086136,-0.02434759,-0.05030516,-0.08054723,-0.0028252993,0.016157858,0.09951458,-0.016256576,0.026515333,-0.0037097854,-0.017808344,0.03946195,-0.01735715,0.03945641,-0.0998351,-0.0017581037,-0.07502168,-0.029473275,0.059324514,0.012350262,0.008977946,0.016984932,-0.055841617,0.003187501,-0.0858927,0.02062944,-0.08017069,0.022771368,-0.014284405,-0.0461173,-0.0072732,-0.052543405,-0.0087639,0.042166434,-0.019574849,0.0153280655,-0.03351968,-0.013898159,-0.0067814155,0.029845444,0.052411035,-0.025312528,-0.0013262538,0.017571008,0.053837255,-0.03267473,0.016202409,-0.014446339,-0.063670784,0.030728323,-0.001135537,0.029808061,-0.016697675,-0.13076629,0.010008482,0.055898465,0.0045169145,-0.05597853,0.069799215,-0.03295101,0.01475288,0.010438398,0.010455201,0.04960626,0.028098393,0.051036015,-0.14765131,-0.07262804,0.049012072,0.014808211,-0.03515436,0.005596328,0.049325828,-0.049946513,0.076437116,0.023216734,-0.07251556,0.05286788,-0.03722014,0.038185608,-0.016539551,