INSERT INTO book_pages (page_number, section, content, embedding, inserted_at, updated_at) VALUES (229, 'Página 229', 'Consideramos ser a intuição produto da sensibilidade intelectual do homem, pois, embora não nasça nele, penetra-lhe a espiritualidade através do filtro sutil do pensamento lógico e se consubstancia, toma forma, no exame crítico da razão pura. Por isso é que grande parte do conhecimento humano provém da intuição a priori confirmada e corporificada pelo raciocínio a posteriori. No uso inteligente da intuição reside a diferença marcante entre o homem e os animais irracionais. O ser irracional, incapaz de elaborar inteligentemente o produto da intuição, desperdiça-o, degrada-o, reduz-lo à condição de simples e elementar faro.

Falar da inspiração do poeta, do descortino do estadista, da visão do empresário, constitui desnecessária tautologia pois nada mais representam que sinônimos da mesma palavra: INTUIÇÃO.

Para a Cibernética a intuição tem grande importância, pois, a partir de certo nível de pilotagem, o racional torna-se incapaz de, sozinho, discernir os rumos a serem imprimidos aos sistemas. Desse patamar, a intuição, como um poderoso radar,', '[0.091874056,-0.021753611,-0.06931065,-0.038020648,-0.023491912,-0.033366222,0.056795713,0.055835616,-0.033064097,0.10324323,0.083819345,-0.024252329,-0.018645722,0.0075595886,-0.004410747,0.022328926,-0.016097551,0.0057616755,-0.040987518,0.073822245,0.099640936,-0.06251916,-0.018717613,0.09698534,-0.03402032,0.035705183,0.023038218,-0.01584568,-0.05115864,-0.04298642,-0.0034143727,0.021218562,0.15378736,-0.006043178,0.028835807,0.039667796,0.03468918,0.010815067,0.012614187,0.03555463,-0.016711477,-0.06123359,-0.08753215,-0.017923776,0.043146882,-0.06978941,0.040665377,0.055551473,-0.0050101047,0.02626504,-0.08622798,0.05211554,-0.053521268,-0.0383311,-0.033210047,0.0166409,0.021505276,0.025347706,-0.007760461,-0.0042271307,0.051856127,-0.057972647,0.047677986,0.04788308,0.046947315,-0.0011986587,-0.018490914,-0.033600435,-0.026124872,0.00645311,0.107552335,-0.032225717,0.031137846,0.049910024,-0.0025969062,0.052908715,-0.02904662,0.012346096,-0.024288401,-0.078697406,0.027648244,0.04290889,-0.0016348554,0.009504954,0.0037516933,-0.017998531,-0.030149225,0.014413833,0.012626012,0.023271095,0.04780679,-0.00016167831,-0.1012231,-0.08507427,0.080575295,-0.011631932,-0.027945317,-0.053922456,0.06290411,-0.017640797,0.031925928,-0.005251984,-0.01898297,-0.020429313,-0.0010749137,-0.019073524,-0.006460955,-0.090179324,-0.020794308,0.09889008,-0.07787163,-0.06623566,-0.06917139,0.014973782,-0.027842358,-0.05637265,0.024783188,-0.061496783,0.04379236,-0.0601365,-0.014535652,-0.037792847,0.055496108,-0.024212463,0.058030758,-0.076144606,-0.0131464945,1.3120696e-32,-0.07906399,-0.0063351835,-0.054393437,0.024008784,-0.0823532,0.032163292,-0.050207574,0.022325475,0.038819764,-0.00019169504,-0.03156275,0.10353339,0.006479721,0.07420246