INSERT INTO book_pages (page_number, section, content, embedding, inserted_at, updated_at) VALUES (233, 'Página 233', 'o que já é uma base de partida, embora pouco ajude no entendimento das propriedades do mecanismo e de seu comportamento.

Sabemos que os sistemas, quando abertos, alimentam-se da energia que importam e que os sistemas fechados, após certo número de transformações, não sendo renováveis suas fontes energéticas, sucumbem à entropia por exaustão da energia que possuíam em reserva. No exemplo, a seguir, trataremos da nutrição nos animais, que são sistemas abertos, examinando, em linhas gerais, como se processa sua função metabólica, cujo papel, na manutenção da homeostase interna, é o mesmo do feedback.

Consideremos o conjunto afim de variáveis ALIMENTAÇÃO-ASSIMILAÇÃO-DESASSIMILAÇÃO.

Importado o alimento do Universo exterior, o organismo do animal, pela função metabólica, assimila o essencial, necessário, e desassimila o excesso e as impurezas. Parte da energia resultante do metabolismo é consumida autofagicamente na realização do processo; a maior parte, entretanto, em condições normais, vai suprir as necessidades internas.', '[0.00042706926,-0.022107955,-0.11461616,0.0118268505,-0.023242781,-0.008098258,-0.01418333,0.10081622,-0.030529616,0.064978264,0.0048944326,-0.030221742,-0.0060606124,-0.058287613,-0.024894845,-0.016356304,0.031413008,0.02291242,-0.026712922,-0.007375184,0.10853177,-0.02986607,-0.07114209,0.06483199,-0.073831394,0.0396139,-0.02471198,0.028801868,-0.060863283,-0.08751255,-0.033450585,0.009735691,0.11897037,-0.06532893,0.013443849,0.07373472,0.041114364,-0.08837393,-0.008358758,0.08242229,-0.061496053,-0.03178714,-0.039651275,-0.026785394,0.0064456696,-0.025453072,0.013998098,-0.016691707,-0.010578763,-0.017498331,-0.091959246,-0.0050478647,-0.073606044,0.042227738,0.015873004,0.007756352,-0.023861092,-0.055787828,-0.05550625,-0.018921064,0.00362846,0.043118082,0.02742065,0.0041221264,-0.002397871,-0.037582044,2.798874e-05,-0.016192699,-0.015099285,-0.033903025,0.040705718,-0.087452166,0.010403464,0.045726474,-0.041772798,0.12024928,0.038985875,0.035421498,0.04414179,-0.08498777,0.02279594,0.014966046,-0.0358805,-0.0439161,-0.014489476,0.04158159,-0.012452307,0.042709302,0.003366097,0.040942606,0.011281396,0.00094804243,-0.05884923,-0.06831708,0.08679276,-0.015992906,0.0067610135,-0.052302033,0.12127447,-0.08386102,0.031644184,0.005406743,0.043160032,-0.013597901,-0.075854905,-0.04751861,0.017487561,0.02397617,0.0882778,0.11174987,-0.07089174,0.012635391,-0.08626124,-0.026959216,-0.028435996,-0.001256415,0.04305508,-0.05374404,-0.0076049655,0.007995396,-0.0060196687,-0.08877514,0.056002054,-0.035936467,0.04188128,-0.033797305,0.040759835,1.0643391e-32,-0.05860844,-0.08174072,-0.0113019,-0.027610632,-0.014161221,0.019576805,