INSERT INTO book_pages (page_number, section, content, embedding, inserted_at, updated_at) VALUES (145, 'Página 145', '> **[Figura 21 — Esquema de ultra-estabilidade de ASHBY. Diagrama com dois subsistemas principais dentro do "UNIVERSO EXTERIOR": o bloco "EVOLUÇÃO" (superior direito) conectado ao marcador OE (círculo superior esquerdo com seta e indicação "OE"), que recebe "Informações" do topo; e o "Sistema de gestão" (inferior direito), contendo os blocos CT, RG e SF interligados, com o marcador O (círculo inferior esquerdo com seta) recebendo VE da parte inferior. O bloco EVOLUÇÃO envia OE ao Sistema de gestão. Dentro do marcador OE há quatro pares de símbolos ⊗–○ indicando comparação de objetivos.]**', '[0.010950519,0.057938855,0.020362487,-0.07941001,-0.11038746,-0.058197748,-0.083652966,0.14764209,-0.0012631739,0.045899298,0.07698115,-0.053012963,0.020912003,0.0037812297,0.027018692,-0.027672771,0.047539935,0.05271623,-0.011816349,0.104599185,0.10585644,-0.04358106,-0.09465712,0.04799877,-0.05030763,0.017555987,-0.044904392,0.01287523,0.0062829675,-0.08674883,-0.028979834,0.008200835,0.10828261,-0.03369607,-0.011786969,-0.026659595,0.047184568,-0.031585597,0.0031344076,0.03622792,-0.11965755,0.021185124,-0.06175599,0.026147563,-0.00020917137,0.028783716,0.0018648739,0.016014408,-0.034634672,-0.082437955,-0.15560734,-0.049102556,-0.059625145,0.031699646,-0.032731082,0.04861507,0.005401455,-0.033510394,0.029724056,-0.01179108,-0.010256062,-0.0068040737,-0.002048792,0.07404579,-0.03793152,0.040327873,0.04371488,0.045714002,-0.10189488,0.08430286,0.10581475,-0.056466278,0.004128637,-0.00035750328,-0.016439304,0.078436,-0.010732455,0.063461244,-0.0058264695,-0.10458776,-0.0069545167,0.016553635,-0.0523563,-0.045086596,0.007951316,0.0042501343,-0.030107556,-0.040111303,0.020089924,0.028451577,0.033937745,-0.01735401,-0.060070883,0.0074038217,0.029841019,0.0015082961,0.013494851,-0.021123245,0.042600837,0.009456953,0.072976105,-0.02270451,0.004941447,0.032727163,-0.