INSERT INTO book_pages (page_number, section, content, embedding, inserted_at, updated_at) VALUES (155, 'Página 155', '— nobreza e clero, parte racional;
— intendentes e guerreiros, parte irascível;
— lacaios, servos e camponeses, parte apetitiva.

A realidade socioeconômica da época medieval apresentou-se, em decorrência de tal modelo, extremamente injusta, pois a parte pretensamente racional, detentora da propriedade material, por sua natureza não se ciente voltava-se, apenas, para a contemplação de Deus, o gozo e a fruição de um paraíso terreno consentido pelo direito divino dos reis. Assim, o clero e a nobreza mantinham-se numa cômoda posição, de alheamento ante as privações que acometiam os servos, lacaios e camponeses, jugulados pelo poder irascível, este, insaciável em colher resultados materiais e implacável em punir os descontentes e os reformistas.

A Revolução Industrial, ao multiplicar os fatores de produção, causando o deslocamento, do campo para a cidade, do centro da atividade econômica, tornou perigosa e, logo em seguida, inviável, a atitude,', '[-0.017274886,0.0603519,-0.019405844,-0.03610824,-0.008239969,-0.018181307,-0.0033160907,0.0934764,-0.03587921,0.05814693,0.106507674,-0.09503351,-0.010299299,0.036405962,-0.011838653,-0.07906959,-0.006853487,0.033388108,0.0022367316,0.13261156,0.15105774,-0.024485936,-0.015918061,0.050057054,-0.06551314,0.060857378,-0.050913367,0.035587687,-0.040594928,-0.06387616,-0.042711567,0.06117731,0.118685454,-0.095113136,0.019103726,-0.0067542153,0.108105235,-0.033034414,-0.033838227,0.07083469,-0.0783086,-0.023685329,-0.036554806,-0.06412086,-0.023740198,-0.010250309,0.049010787,0.014770067,0.021609914,-0.037100825,-0.031119544,-0.0436537,-0.019414907,0.0071615763,0.0010876718,-0.04922367,-0.037517227,-0.08334517,0.0062407446,0.046586845,-0.044652216,0.040008783,-0.047170423,0.012631808,0.036617313,-0.03532984,-0.0037403428,-0.030028382,-0.05021416,0.02961177,0.073163606,-0.1181885,0.04277913,-0.04735084,-0.054669943,0.09749335,0.038908903,0.0028506902,-0.03374317,-0.106722176,-0.03113755,0.028993087,-0.017305518,-0.008087907,-0.024663689,-0.018227931,0.0071969377,0.0020640285,0.10659885,0.0033151302,0.007101237,0.09717121,-0.12331011,-0.025369635,0.045545973,0.03834184,-0.026045436,0.044363096,0.025104593,0.008535305,0.034595154,-0.05621437,-0.002301014,-0.05643444,-0.044392437,-0.0045138826,-0.009144284,-0.04948738,0.0071840803,0.06603018,-0.12381869,-0.038298614,-0.10520539,-0.01600942,-0.07356458,-0.016665075,0.0468135,-0.10605406,0.022301318,0.053346593,-0.019033056,-0.044772573,0.024254033,0.007792983,0.083638474,-0.005793985,0.1102421,1.0130679e-32,-0.08630098,-0.09286479,-0.0045049298,-0.0062532853,0.047919247,0.03371474,-0.052389387,0.013706786,0.06313431,-0.042927116,-0.009290932,0.08162599,-0.043017466,0.04390577,0.12640758,-0.046588354,0.08533399,-0.051535595