INSERT INTO book_pages (page_number, section, content, embedding, inserted_at, updated_at) VALUES (206, 'Página 206', 'atualizados dessa apropriação, mas como esta é a primeira operação do sistema, tais valores serão levantados por meio dos métodos de que dispõe a administração da produção para esse fim.

Normalmente considera-se como devendo pertencer à classe A itens (ou TE) que correspondem a 20% das requisições acumuladas e onerem em 65% os custos totais; à classe B, 30% e 25%, e à classe C, 50% e 10% respectivamente.

A curva ABC é um diagrama cartesiano em que a frequência dos itens (ou TE) é lançada, segundo sua classe respectiva, em um dos eixos, enquanto os valores acumulados são lançados no outro eixo. Ela oferece uma visão bastante rica de informações, a respeito da composição dos itens de materiais e das TE do processo produtivo, segundo a importância desses elementos relacionada a custos.

O outro instrumento de definição do trabalho, a EDT — estrutura de divisão do trabalho — é uma espécie de árvore genealógica das famílias de produtos acabados.', '[0.07402478,0.009537967,-0.037655156,-0.081941344,-0.0032815035,0.00094279234,0.017335963,0.047337167,0.034663543,0.10103752,0.07935423,-0.0811245,0.024555845,0.0076622367,0.009127359,-0.028813502,0.009522305,-0.00047271018,-0.10398989,0.019408746,0.12595285,-0.0387717,-0.052051846,0.027743138,-0.097078264,0.051024158,-0.031890716,-0.024353491,-0.07884287,-0.07764528,-0.036932234,0.09887502,0.098743975,0.04447844,-0.039005533,-0.0018271741,0.065078884,-0.032542,0.011088572,0.08632058,-0.08318326,-0.0071740393,0.014817287,0.0027060395,0.003920044,0.007563182,0.06840766,0.001010364,0.0197116,-0.00829018,-0.036069397,0.029391777,-0.09691127,-0.035562675,-0.0406434,-0.009090316,0.051140383,-0.065629736,0.026968664,-0.01710489,-0.029107258,-0.021123828,0.020848664,0.06888081,0.016668769,0.0015782658,-0.022163985,-0.020393096,-0.061712284,0.01075668,0.02891631,-0.02051568,-0.016339198,0.07462715,0.017640421,0.13843663,-0.0016564912,0.024485067,-0.05209929,-0.11537152,-0.039168168,0.055851758,-0.007017765,-0.056667592,0.020602934,0.0045016683,0.0028939585,0.014336721,0.027577603,0.04019974,0.032277968,0.040342078,-0.065757714,-0.04110994,0.027106402,0.0076454636,0.024292406,-0.051859338,0.0327646,-0.04539375,0.053768396,-0.010191121,0.003687919,-0.020858552,-0.057673853,-0.042844836,-0.016000556,-0.024454582,0.08500386,0.08724319,-0.106086425,-0.043001,-0.14490001,0.002667808,-0.07258885,-0.016855156,0.012969016,-0.057650913,0.027350463,-0.01200243,0.0253098,-0.075092115,0.037848853,-0.013742597,0.026203163,-0.074602276,-0.0035326793,8.686759e-33,-0.07278527,-0.057600982,-0.019933581,-0.0024887517,0.024000663,0.003771974,-0.07281205,0.042625006,0.08969619,-0.0063422066,-0.09617875,0.094721645,0.013919856,0.053175524,0.12396913,0.036341213,0.03189444,0.01636087,-0.021965357,-0.012287434,-0.084309034,0.0444802,0.02