INSERT INTO book_pages (page_number, section, content, embedding, inserted_at, updated_at) VALUES (164, 'Os Críticos do Modelo', 'Para encerrar este tópico, relativo à Anatomia da Pilotagem, apresentamos a figura 24, que nos parece ser a imbricação do modelo neurofisiológico com a organização empresarial. As conclusões — e há muitas, a serem extraídas — deixamos por conta do leitor.

### Os Críticos do Modelo

Os críticos do modelo neurofisiológico — evidentemente que não os há entre os cibernetas — reagem à ideia de que a empresa, tal como o organismo, deva aproveitar-se, ao máximo, da faculdade de agir autonomamente, e que a cada nível da hierarquia de controle deva corresponder um grau, equivalente, de autonomia. Estes, postulam uma administração altamente centralizada, e pensam que o computador tornará isto possível, como uma máquina milagrosa, capaz de lhes proporcionar recursos técnicos para a resolução de todos os problemas em qualquer nível.

---

*(Continuação da pág. anterior) Esta expressão — informática — tem sido empregada, frequentemente, num sentido estrito, como se devesse referir-se, unicamente, ao processamento de dados, o que é uma meia verdade. Voltaremos ao assunto, mais adiante.*', '[0.031740688,-0.021952698,-0.06821895,-0.04351432,-0.08539943,0.050444167,-0.007669754,0.10615131,0.03319436,0.10821889,0.046295583,-0.02514554,0.014339788,-0.02779922,0.006850524,0.042183317,0.007439604,-0.0005930527,-0.024161449,0.042699218,0.1347498,-0.039057776,-0.08484194,0.07374538,-0.069325335,0.0015746985,-0.049749326,0.020292262,-0.09424836,-0.066467814,-0.05162957,0.054981843,0.11883998,-0.010974507,0.009664496,0.008390499,0.00748101,-0.05465566,-0.03543401,0.026642961,-0.064230755,-0.024399703,-0.0452758,-0.02897018,-0.012719152,-0.0111213,0.032198474,0.013466386,-0.06361765,-0.01740732,-0.068155594,-0.07827477,-0.011429708,-0.032067906,0.058093224,-0.027592378,-0.036308516,0.0051677455,0.007765392,-0.045696367,-0.047924764,0.049504932,-0.04464242,0.0097714905,0.051229615,0.014725926,-0.028813055,-0.06377727,-0.037041467,-0.03305776,0.033509005,-0.12329828,-0.014927555,-0.05829037,-0.009931176,0.058642935,-0.010573848,0.06085616,0.10168421,-0.11605968,0.024760492,0.085147485,-0.042897046,-0.0134826675,0.01392573,0.01298995,-0.002166902,0.047428362,0.04124183,0.031597704,-0.036707163,-0.0077116587,-0.0758731,-0.037196446,0.030553496,0.0051713944,0.005208567,-0.052800078,0.0752683,-0.0035892196,0.08427576,0.021609316,0.029641699,0.0104846945,-0.037187684,-0.017870098,0.05158292,-0.06431865,0.029028982,0.053907834,-0.12742655,-0.018871237,-0.091983095,-0.02811693,0.036557235,-0.006315967,-0.022265615,0.020126583,0.044416223,-0.04019025,-0.035211835,-0.0978004,0.025044538,-0.08029365,0.061494872,-0.017279863,-0.0678312,1.0789244e-32,-0.051732462,-0.060734674,-0.025578134,0.025376113,0.053401336,0.0067665465,-0.04014274,0.028109426,0.07970148,0.011562004,-0.15621027,0.08089491,-0.0049503734,0.07749277,0.1044469