INSERT INTO book_pages (page_number, section, content, embedding, inserted_at, updated_at) VALUES (178, 'Página 178', 'te método, dada a magnitude da tarefa global, programada, só teve condições de aplicação devido ao computador. Outra coisa que se pode afirmar, ainda que intuitivamente pois não há dados a respeito, é que nenhum dos problemas a seguir mereceu preocupações maiores por parte dos pesquisadores e dos executores do projeto: elaboração das folhas de pagamento do pessoal do projeto e controle de contas a pagar!

O projeto Polaris consistiu, ciberneticamente, na concepção de um sistema de gestão dotado de variedade suficiente para operar um sistema físico extremamente complexo e cujas restrições ao estabelecimento de um permanente estado de ultra-estabilidade decorriam das probabilidades, acumuladas, de inadimplência por parte de onze mil fornecedores, responsáveis pela entrega de dez milhões de itens a serem aplicados no decurso de prazos sequenciais necessàriamente rígidos e apertados: A descrição do sistema através de uma rede PERT que continha informações detalhadas sobre o desdobramento das suas sucessivas condições, no tempo e no espaço, possibilitou o emprego do computador', '[-0.02951616,-0.024621185,-0.109238856,-0.022267697,-0.056731362,-0.030067928,-0.020822309,0.12156352,0.00984084,0.11385966,0.1103241,0.013683983,0.0067101005,0.03590532,0.02609558,0.01651133,0.025640914,-0.026557999,-0.06824704,0.025901636,0.10545118,-0.048609134,-0.05295262,-0.007316059,-0.12822494,0.034294892,-0.022124141,-0.012777938,-0.05636995,-0.02704265,-0.017979957,0.063824244,0.11206261,-0.020107158,-0.013587398,0.057085875,0.002214453,-0.07741669,-0.031555332,0.056122106,-0.07744182,-0.04941407,-0.046160966,-0.12770727,-0.025083767,0.0054714736,0.05576269,0.0026624077,-0.039863795,-0.066307895,-0.062282696,-0.035238996,-0.020622304,-0.005904741,0.056597628,-0.04251357,0.031786375,-0.06031032,-0.002834845,-0.019083578,-0.065755956,0.0054296246,-0.045470227,-0.016989993,0.0312569,0.021184832,0.0023277276,-0.034661073,0.0063557858,0.02233502,0.018413085,-0.031612936,0.024482716,0.019150807,0.01582507,0.02776349,-0.0014022852,0.026472658,0.0060280534,-0.13984929,0.032962948,-0.020536525,-0.053550538,-0.04129582,0.06944353,0.020996854,0.038594212,0.05571719,0.045230314,0.0066921934,-0.032076467,0.060553923,-0.07511234,-0.04438396,0.017492568,0.024081133,0.03160254,-0.052741565,0.012475803,-0.07790582,0.07395762,-0.038324423,-0.06550689,-0.025088752,-0.061772734,-0.059313454,0.019651886,-0.0