INSERT INTO book_pages (page_number, section, content, embedding, inserted_at, updated_at) VALUES (232, 'FEEDBACK', '## FEEDBACK

Os mecanismos de auto-regulação por feedback trazem em si grande importância, qualquer que seja seu campo de aplicação, que vai da biologia à física, da matemática à sociologia, enfim, participam de quase todos os fenômenos de que a Ciência se ocupa. Por serem, entretanto, pouco conhecidos é que se lhes dedica este apêndice especial, em que serão exploradas três aplicações: na biologia, na economia e na matemática.

A razão de se tratar de uma palavra empregada quase que exclusivamente em sua grafia original — embora já se observe uma tendência ao uso da forma aportuguesada: fidibeque — reside no fato de não ser possível obter-se, por tradução a mais livre que se faça, um termo capaz de exprimir o conceito oriundo do inglês. Contentemo-nos, pois, inicialmente em saber que a etimologia indica tratar-se de retro-alimentação,', '[-0.014832218,0.054589566,-0.04206351,-0.02151971,-0.017476395,0.009140901,0.005291184,0.036082134,-0.0076161874,0.1139151,0.0782258,-0.066224806,-0.048423517,0.012198704,-0.02308768,0.033019092,-0.024905061,0.009201938,0.011212781,0.07472956,0.14548825,-0.051895216,-0.022557162,0.061341014,-0.09841395,0.0038194584,-0.05152068,0.014721612,-0.033847384,-0.070084535,-0.06995161,0.11221897,0.16251566,-0.03845672,-0.014837472,0.011509852,0.045726463,-0.01881416,-0.034770977,0.033516232,-0.07045103,-0.046480943,0.0012148991,-0.07093109,-0.030147634,-0.04338303,0.036551785,0.021672038,-0.028758414,-0.03731973,-0.0894428,-0.003951027,-0.0410255,-0.00067638303,0.01851367,-0.018049825,0.048564017,-0.0045416974,0.004248263,-0.024103038,0.04746011,0.0416679,-0.063184984,0.034667693,0.009489735,-0.04328426,-0.055186983,0.012810804,-0.0122094285,0.074216284,0.017161813,-0.11542574,0.009128035,0.011861792,0.034224678,0.11436507,-0.07146202,0.03359566,-0.012075572,-0.089385934,-0.007882267,-0.03138362,-0.039804872,-0.06677479,-0.04899362,-0.030451164,-0.021977901,0.003417784,0.00052142877,0.049527414,-0.020779345,0.06034703,-0.04404859,-0.014701191,-0.013986623,0.03756389,-0.02625103,-0.028579237,0.11326797,-0.041209202,0.055829205,0.06401845,0.0068753143,0.0057445415,-0.056521527,-0.06331618,-0.06322381,-0.030252155,0.078032345,0.114610784,-0.09529429,-0.048910853,-0.09157549,0.033495218,0.000610698,-0.009897047,-0.00784454,-0.055679034,0.050674457,0.037133697,0.03401446,-0.063078016,0.039256655,-0.07380566,0.13535015,-0.016321724,-0.028482111,1.0947758e-32,0.007710817,