INSERT INTO book_pages (page_number, section, content, embedding, inserted_at, updated_at) VALUES (212, 'Página 212', '> **[Figura 27 — Grafo das atividades de programação e controle da produção. Diagrama com nós circulares interligados por setas. Na base: nó "1 P.P" (Programação da Produção) conectado a "1.1 PE", "1.1.1 PCCAO", "1.1.2 PCCAI", "1.2 PF" e "1.3.1 PCCP". Esses nós convergem para "2 ARO" (Alocação de Recursos e Orçamentação). De ARO parte seta para "3 C.P" (Controle da Produção), que se conecta a "3.1 PPE" e "3.2 PPR". De C.P e dos nós laterais partem setas para "4 AR" (Auto-Regulação) no topo.]**

