INSERT INTO book_pages (page_number, section, content, embedding, inserted_at, updated_at) VALUES (219, 'Página 219', '> **[Fig 29 — Gráfico de sinergia e oscilação do sistema. Diagrama com eixo horizontal representando os centros de custos na sequência: CCP, CCAI, CCAO₁, CCAO₂, CCAO₃, CCAO₄, CCAO₅, CCAO₆, CCAO₇, CCAO₈. Duas linhas percorrem o gráfico: a linha de sinergia real (performance real), tracejada, e a linha de sinergia virtual (performance estimada), contínua. A escala vertical indica 100% e 160%. O ponto CCAO₈ atinge 160% na linha real, indicando desvio acentuado.]**

