INSERT INTO book_pages (page_number, section, content, embedding, inserted_at, updated_at) VALUES (199, 'Página 199', '> **[Figura 25 — Organograma (simplificado) da ALPHA. Estrutura hierárquica com PRESIDENTE no topo, ligado a três assessorias: Infor(mática), Control(er) e Vice-Pres(idente). O Vice-Presidente se conecta a quatro departamentos: Pes(soal), Finan(ceiro), Prod(ução) e Com(ercial), além de Adm(inistração). Cada departamento possui subdivisões em D Sv (Divisão de Serviços) com CCAO (Centro de Custos Auxiliares Operacionais) e, no caso de Produção, também D Sv CCP (Centro de Custo de Produção) e CCAI (Centro de Custos Auxiliares Indiretos). Os departamentos Com e Adm possuem apenas CCAO diretamente ligados. Legenda: CCP = Centro de custo de produção; CCAI = centro de custos auxiliares indiretos.]**', '[0.046670545,-0.020218296,-0.064664125,-0.08725277,-0.016161432,0.023846202,-0.03910869,0.1334146,0.046084836,0.05108182,0.11371739,-0.08704523,-0.0021599978,0.017332565,-0.025868246,-0.0948953,0.012186002,0.014150512,0.0682986,0.07443815,0.090730436,-0.076434486,-0.08487265,-0.0041732998,-0.07289015,0.047903955,-0.015425637,-0.034270138,-0.05356796,-0.08173444,-0.042360485,-0.020706289,0.13641343,-0.010998154,0.035734624,-0.026853148,0.008751683,-0.045355882,-0.0056207753,0.05797791,-0.019835059,0.030887792,-0.044705458,-0.0533748,0.034144185,0.03197994,0.047758523,0.041788977,-0.0136371,-0.03241433,-0.015187363,0.011119786,-0.022841841,0.029696276,-0.03432289,-0.057906203,-0.008414982,-0.076837786,0.015976598,0.010425387,0.0030567686,-0.0116610555,-0.034686945,0.033441424,-0.012690278,-0.044471897,-0.015638238,0.0009558415,-0.07698525,0.020893626,0.040490203,-0.074065104,-0.051008824,0.075862855,-0.064369366,0.12094766,0.04457722,0.07706123,0.105850354,-0.17485759,0.025394423,0.074936844,-0.023588909,-0.03348909,0.023753982,0.06762289,0.01874046,-0.06720288,0.035232056,-0.03945087,0.021719327,0.040010624,-0.05569792,-0.004734172,-0.016558541,-0.028410103,-