INSERT INTO book_pages (page_number, section, content, embedding, inserted_at, updated_at) VALUES (205, 'Página 205', 'A classificação ABC dos itens de materiais e das tarefas elementares constitui um dos instrumentos de definição do trabalho. Sua apresentação geométrica é a curva ABC, muito usada no controle de estoque embora não seja esta sua única finalidade, conforme veremos.

Duas listas servem de base para realizar-se a classificação ABC: as folhas de materiais por itens ABC e as folhas de operadores (manuais e de máquinas) por tarefas elementares ABC.

As folhas de materiais destinam-se à anotação dos itens aplicados ao produto, os quais são identificados por meio de um código numérico fornecido pela contabilidade financeira.

As folhas de operadores destinam-se à anotação das TE, e, da mesma forma que os itens, são identificados numericamente.

A inclusão de um determinado item ou TE na classe A, B ou C depende da apropriação de seu custo. Se o SIPCP da ALPHA já estivesse operando há alguns exercícios, seu banco de dados forneceria os valores', '[-0.016969362,0.04191968,-0.031099994,-0.03706479,-0.06683903,0.022570644,0.024946798,0.022670632,-0.013203881,0.05169005,0.03052858,-0.11283672,-0.011564415,0.02133979,-0.0023548948,-0.019698543,-0.054524172,0.007528236,-0.042115677,0.13990983,0.15709947,0.01862666,-0.05544216,0.08033263,-0.08155381,0.044629987,-0.059523024,0.019467827,-0.048149038,-0.10484107,-0.06458838,0.06994201,0.14314261,-0.0071010664,0.010157333,-0.033148017,0.0020830205,-0.014508842,0.007723986,0.1067789,-0.04989502,0.0053596147,-0.033769235,-0.015573009,-0.04778508,-0.012706798,0.0909988,0.00913052,0.010148433,-0.014156699,-0.10273959,0.004501993,-0.118649386,0.01125548,-0.0096155815,-0.032606263,0.022596886,-0.01641535,0.005353604,-0.03231298,0.017948603,0.047860038,0.03857962,0.041750308,-0.0049961885,0.036696568,-0.02684645,-0.06298642,-0.057952903,0.053682502,0.06022573,-0.056583174,0.021982778,0.026004456,0.004653312,0.12999585,-0.0034882186,0.0043032044,-0.01673271,-0.08824453,-0.083240636,-9.7226366e-05,-0.06449968,-0.08128218,0.039079472,0.043029938,0.0036762813,-0.00028698245,0.009591729,0.032087546,-0.0095064035,0.0073417984,-0.051954318,-0.06012031,0.05859621,0.016315296,0.006752999,-0.049223773,0.0924667,-0.06312154,0.059985008,-0.0035017089,0.004635868,0.01710389,-0.034733508,-0.0026419614,-0.0011767412,-0.06990296,0.033760153,0.0682849,-0.03226535,-0.054582626,-0.1411739,0.0065589137,-0.09918342,-0.0100740325,-0.04123779,-0.092692204,0.069047496,-0.043900874,0.05413814,-0.09545423,0.09518723,-0.0011598764,0.03285999,-0.00818096,-0.054423183,7.698747e-33,-0.08657824,-0.040643137,-0.0097875055,-0.04204511,-0.002333359,-0.028087992,-0.08075495,0.08110067,0.058574636,0.047898218,-0.08566362,0.13145678,0.0061902795,0.035917625,0.08641798,0.0029266484,0.05684491,-0.035194978,-0.03