INSERT INTO book_pages (page_number, section, content, embedding, inserted_at, updated_at) VALUES (226, 'INTUIÇÃO', '## INTUIÇÃO

A intuição constitui, inegavelmente, um dom, raro, do espírito humano e uma de suas mais sutis manifestações. Não há quem lhe desconheça os efeitos, embora a Ciência teime em lhe negar o acesso ao pódio erguido desde os primórdios da criação da Lógica Material para homenagear as conquistas creditadas à indução e à dedução, injustamente considerados os únicos instrumentos formais da atividade intelectual.

A importância da intuição decorre, precisamente, do fato de ocupar os espaços vazios deixados pela dualidade do método, incapaz, frequentemente, de oferecer uma resposta satisfatória à dúvida cartesiana: de onde surgiu a idéia inicial...? Tanto a indução como a dedução precisam partir de um conhecimento básico, pré-existente, para, pela síntese ou pela análise, erigindo sobre essa pedra fundamental o edifício do meto', '[0.0019470061,-0.025095122,-0.038086224,-0.032758035,-0.01340685,-0.020189436,0.028851312,0.06896813,0.0014925108,0.10499213,0.054605257,-0.019819167,-0.0060356883,-0.010850901,-0.017697453,-0.030056067,0.010433391,0.021218924,-0.04934321,0.07260518,0.17281136,-0.051797934,-0.0447304,0.0478954,-0.107179925,0.019724913,-0.011402777,-0.015377719,-0.06942551,-0.024871238,0.01497485,0.026255142,0.13623008,-0.05723096,0.01813756,0.0016646499,0.09634573,-0.0896781,0.016903082,0.017142607,-0.08191401,-0.06949162,-0.08372731,0.0016808602,-0.010966799,-0.041537937,0.010223722,0.06721449,-0.018079562,-0.030964838,-0.032038424,0.0037588975,-0.08229628,-0.028491566,-0.02425061,0.005050669,-0.023489675,-0.01569915,0.048580963,0.0073553943,0.007070943,0.045861803,0.048197675,0.07282262,0.011066072,0.022363212,-0.0169566,0.0024368672,-0.0045763925,0.044541992,0.09573471,-0.061982244,0.05667142,0.0415622,-0.014089853,0.06666176,0.020886287,0.01378645,-0.061773103,-0.13807862,-0.022619944,0.05283016,-0.018114144,-0.023811694,0.009923801,0.0018241891,-0.03333148,0.0600859,-0.0012755435,-0.01448892,0.058875833,0.0066906656,-0.08211421,-0.039481767,0.050119326,-0.029451385,-0.03410509,-0.018691294,0.10037049,-0.035928287,0.024846468,-0.012318786,0.041617148,-0.018452758,-0.030552536,-0.020608852,-0.02913447,-0.091749236,0.043338653,0.084687345,-0.062597126,-0.063849494,-0.0953398,0.021013994,-0.045167666,-0.009463913,0.020896709,-0.067194976,0.036448304,-0.07398349,0.021611784,-0.099618845,0.0963137,-0.045407712,0.05304717,-0.052776203,0.009979599,1.1092791e-32,-0.06999