INSERT INTO book_pages (page_number, section, content, embedding, inserted_at, updated_at) VALUES (213, 'Página 213', 'manos e físicos de toda a sorte — ocupa seus postos como um exército que, ao soar dos clarins, apresta-se para o combate. A orçamentação constitui uma modalidade de controle, baseada na apropriação dos custos e despesas a serem incorridos. Outras modalidades de controle serão, também, exercidas pelo SIPCP, tal como controle de qualidade e de tempo³, mas nos deteremos, apenas, no controle sobre os custos e despesas.

Os orçamentos colunares flexíveis⁴,

---

3. *PERT/custo e PERT/tempo são técnicas de controle de projeto que oferecem substanciais vantagens quando as transformações do sistema operado implicam número muito elevado de transições. Daí o seu emprego no controle do projeto polaris e na indústria de construção civil.*

4. *Poderá parecer, à primeira vista, paradoxal utilizar orçamentos colunares flexíveis quando se sabe que 100% do potencial produtivo será absorvido pelo mercado. Atente-se, entretanto, para o fato de que a capacidade dos centros de custos foi apenas avaliada (não é a mesma coisa que ser medida), tratando-se, assim, de dados teóricos, sujeitos a correções posteriores. Ademais, as linhas orçamentárias constituem o que se pensa e se pretende de va ser o funcionamento sinérgico do sistema alpha.*', '[-0.08050647,0.009442906,-0.08210106,-0.03773723,-0.045397855,-0.014398499,-0.006737725,0.09566705,0.049066603,0.08521599,0.13497911,-0.045946088,0.013718194,0.002826493,0.009311862,0.028208401,-0.024917832,0.02456222,-0.012164853,0.07527472,0.116348505,-0.05788226,-0.058538795,0.04290964,-0.11353363,0.050110642,-0.07082245,0.017135158,-0.032471724,-0.07818826,-0.039005447,0.030054804,0.07082221,-0.040115405,0.0072893715,-0.0060411966,0.062103998,-0.10183658,-0.07455594,0.1045525,-0.08427517,0.008673858,-0.07615023,-0.109228864,-0.023870911,0.01536379,0.080624595,0.00903786,-0.013617555,-0.13058916,-0.025116105,-0.021344384,-0.029690003,-0.018266212,0.013119059,-0.06181447,-0.0025697495,-0.030174108,0.07653224,-0.047105372,-0.011891436,0.022570068,-0.059199795,0.012207246,-0.0127797825,0.018932253,-0.013104789,-0.024772914,-0.0203968,0.02142935,0.036053967,-0.05625706,0.009812423,0.007362158,-0.016198585,0.077826716,0.017693583,0.062135756,-0.04137462,-0.13602893,0.055770934,0.013117093,-0.041880567,-0.021381604,0.028637419,-0.0050807004,0.013526462,-0.0076513602,0.07374332,0.041831747,-0.065651596,0.030406402,-0.112058505,-0.076017566,0.08100487,-0.0019388306,-0.0019281213,-0.020237457,0.02230499,-0.042423893,0.07865731,-0.0057957103,-0.082854725,0.03070807,-0.0087282285,0.020942003,-0.022426495,-0.022433683,0.029916275,0.10335756,-0.054422174,-0.038631115,-0.10215601,-0.06153719,-0.037842996,-0.009416838,-0.038508445,-0.06368316,0.05127058,-0.0014876073,0.01848243,-0.117