INSERT INTO book_pages (page_number, section, content, embedding, inserted_at, updated_at) VALUES (234, 'Página 234', 'É de fácil inferência que tanto uma entrada insuficiente quanto eventuais excessos serão mal recebidos: no primeiro caso, por razões óbvias; no segundo caso, além do desperdício, o organismo terá que realizar um trabalho extra de metabolização do excesso, com um consumo de energia que poderia ter sido evitado. O organismo se precavêm, filogeneticamente, contra tais inconvenientes: quando estudamos o terceiro nível de pilotagem vimos que a ação supletiva de EVOLUÇÃO tem, em certos casos, caráter didático no sentido de reciclar os conhecimentos de GESTÃO. O sistema, assim, vai-se tornando cada vez mais apto, pelo aprendizado. E aprende, entre outras coisas, a regular a entrada exatamente no quantum satis, por uma questão de economia orgânica e de relacionamento sinérgica com o sistema maior ao qual se integra, com o qual interage e se inter-relaciona. Esse controle hemeostático, que todo sistema traz implícito em seu projeto e que a experiência acumulada — aprendizagem — torna paulatinamente mais eficaz, tem, no animal, como instrumento principal de execução, a função metabólica.', '[0.020248275,0.031033382,-0.062004454,-0.018082941,-0.043667845,-0.045827083,0.002126532,0.11806458,0.028233254,0.10557664,0.116669364,-0.012356313,-0.023648364,0.03878422,0.027216138,0.006793176,0.021003662,0.018949479,-0.06906975,0.06339115,0.11136884,-0.061607167,-0.10953256,0.068083264,-0.11990183,0.0011283954,-0.031787325,-0.009967027,-0.0726661,-0.08262079,-0.026069041,0.10547096,0.111306965,-0.063941464,0.080057666,0.009780281,0.02411976,-0.04906239,-0.05320738,0.0238059,-0.06878747,-0.026649598,-0.068367995,-0.0074434835,-0.012306053,-0.04160166,0.018749043,0.005387809,0.005221071,-0.054745767,-0.031081297,0.019470084,-0.0461385,0.053637296,-0.01144229,-0.07408487,0.00540388,-0.04299158,-0.076129824,-0.041045222,-0.0066762613,0.0071359496,-0.024154669,-0.0037612547