INSERT INTO book_pages (page_number, section, content, embedding, inserted_at, updated_at) VALUES (253, 'Página 253', 'fato, a cada dia, através de uma luta que se trava no campo de batalha da economia contra exércitos cujas principais armas são a Ciência e a Tecnologia. E, nessa trincheira de luta, que passo a ocupar a partir de agora, sinto-me orgulhoso de ombrear-me com os ilustres colegas que me antecederam na conquista deste honroso laurel. Sinto-me, também, no dever de externar à Companhia Cervejaria Brahma, empresa genuinamente brasileira, um preito de gratidão e de reconhecimento pelo grande serviço que presta à nossa querida Pátria ao incentivar a formação de profissionais cada vez mais competentes no campo da administração de empresas.', '[0.026236588,0.060057368,-0.04090249,0.01946639,-0.021236759,-0.018918626,0.03083143,0.049143482,0.03795716,0.072450176,0.062504984,-0.10847859,-0.06656782,0.02474411,0.018719548,-0.051163353,-0.0073909913,0.0048178737,0.02110173,0.0998093,0.07462304,-0.05861315,-0.055643097,0.049365107,-0.055517636,-0.02490362,-0.014006769,-0.0062959976,-0.052784935,-0.051670868,0.042251017,0.049171876,0.14908159,-0.022065377,0.002402641,0.032074757,0.027936371,-0.060118858,-0.029933924,0.07626108,-0.0124518005,0.007937252,-0.049970232,-0.10715602,-0.017016016,-0.04060372,0.07216221,0.09087789,-0.05529181,-0.0069139055,-0.018293487,-0.029163081,-0.060445946,0.014253556,-0.021435497,-0.0460744,0.012836102,-0.0424036,-0.019057924,0.059311263,-0.01906339,0.049216438,-0.017253103,0.012794543,0.027984552,-0.072859526,-0.02273204,0.033667803,-0.014605999,0.011421305,0.060412023,-0.09673993,-0.070659816,0.029835606,-0.06583531,0.09324233,-0.013152678,0.12662931,0.061150253,-0.12603554,0.010387719,0.049060848,-0.031667896,-0.030973671,-0.0017302862,-0.0078337,0.00011924962,0.020872097,0.049172513,-0.009829384,0.020238053,0.063317046,-0.112876065,-0.015255763,-0.036481928,-0.017536655,0.04536525,-0.025479067,0.030199097,-0.025434062,0.010414323,-