INSERT INTO book_pages (page_number, section, content, embedding, inserted_at, updated_at) VALUES (252, 'Página 252', 'ca do adolescente transmutado no vibrante cadete, os sólidos fundamentos de uma cultura científica, sistemática e organizada. Já como oficial, sob o regime espartano da caserna, no dia a dia de uma carreira em que os sacrifícios se compensam pelo sentimento do dever cumprido perante o altar da Pátria, aprendi, talvez, a maior lição de minha vida: a de que é mais importante dar de si do que pensar em si!

A Universidade do Amazonas, onde me graduei em Administração de Empresas e Ciências Contábeis, e onde, hoje, realizo o pós-graduação em contabilidade gerencial, devo, pela qualidade do ensino ministrado e pelo exemplo frutificante de seus mestres, sempre devotados às nobres causas do bem comum, a motivação e o apoio sem o qual teria sido impossível aceitar e vencer este grande desafio.

No mundo de hoje, em que as fronteiras políticas vêm sendo subrepticiamente transpostas pelas corporações multinacionais, a soberania das nações não se garante mais, unicamente, pelas normas do Direito Internacional: precisa ser reconquistada, de', '[0.05115102,0.087224215,-0.029647445,-0.03179669,-0.0461173,0.019272303,0.0070088934,0.09243576,0.07189185,0.05298768,0.10408846,-0.06374282,-0.036507357,0.02388203,-0.012261133,-0.01069617,-0.006738294,0.020304542,-0.034517605,0.0036312775,0.098138414,-0.031628244,-0.062019818,0.07483554,-0.13514513,0.0385932,-0.004360716,-0.037722398,-0.017703775,0.016015165,0.011745786,0.06320698,0.112393826,-0.013755756,-0.008868385,0.05920367,0.06802275,-0.009244162,-0.025528232,0.091741435,-0.10305428,0.023239717,-0.06372464,-0.07742853,0.004693503,-0.10659854,0.074366294,0.020667445,-0.04639619,-0.015866,-0.04690164,-0.011586675,-0.030366963,-0.02947045,0.052436516,-0.042127606,-0.0049001696,-0.01810623,0.01612209,0.030443354,-0.05545732,-0.023743385,0.012229589,0.01669065,0.024654519,-0.017004082,0.005297011,0.0025290165,-0.023925839,0.03810267,0.039549876,-0.107826546,0.0039048572,0.0717035,0.0098786,0.12407614,0.009018771,0.060669355,0.033149254,-0.07238849,0.036916047,0.038913153,-0.0762866,-0.028418766,-0.021198383,-0.054187648,0.0043363217,-0.017646726,0.0008910619,0.02605638,-0.014043221,0.020466212,-0.061450534,-0.0059824823,0.035626505,-0.025441544,-0.04160299,-0.04711925,0.036478467,-0.06564543,0.058312237,0.06972033,0.025540633,0.030567069,-0.08636731,-0.042303823,-0.0009307329,-0.06235522,0.015743392,0.11108935,-0.047150668,0.0047218977,-0.061665423,-0.05610734,-0.0073992377,-0.0037691584,-0.039845094,-0.009184937,-0.004443598,0.05132312,-0.014706598,-0.07766099,0.036174074,-0.04986955,0.023306217,-0.079139076,-0.005251555,8.23311e-33,-0.0045521674,-0.04267742,-0.039862964,0.0028543933,-0.015615485,-0.0022217936,0.053542264,0.046144914,0.053509653,-0.045461215,-0.05153552,0.018024009,-0.0038602836,0.016788378,0.1178837